#requires -version 5.1
$ErrorActionPreference = "Stop"

# Resolve the directory containing the running PS1 or compiled EXE.
# PS2EXE leaves $PSScriptRoot empty in compiled applications. Some PS2EXE
# environments also fail to populate $ScriptRoot, so the process executable
# path is used as an independent fallback.
$ApplicationRoot = $null

if (-not [string]::IsNullOrWhiteSpace($PSScriptRoot)) {
    $ApplicationRoot = $PSScriptRoot
}
elseif (-not [string]::IsNullOrWhiteSpace($ScriptRoot)) {
    $ApplicationRoot = $ScriptRoot
}
else {
    try {
        $currentExecutablePath = (
            [System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName
        )

        if (-not [string]::IsNullOrWhiteSpace($currentExecutablePath)) {
            $ApplicationRoot = [System.IO.Path]::GetDirectoryName(
                $currentExecutablePath
            )
        }
    }
    catch {
        $ApplicationRoot = $null
    }
}

if ([string]::IsNullOrWhiteSpace($ApplicationRoot)) {
    $ApplicationRoot = [System.AppDomain]::CurrentDomain.BaseDirectory
}

if ([string]::IsNullOrWhiteSpace($ApplicationRoot)) {
    throw "The application folder could not be determined."
}

$ApplicationRoot = [System.IO.Path]::GetFullPath($ApplicationRoot)
$ConfigurationFolder = Join-Path $ApplicationRoot "Configuration"
$SettingsPath = Join-Path $ConfigurationFolder "settings.json"
$LogsFolder = Join-Path $ApplicationRoot "Logs"
$DiagnosticsFolder = Join-Path $LogsFolder "Diagnostics"

# ============================================================
# SYYBOTT'S MEDIA OPTIMIZER v1.0.0-beta.1
# Embedded engine: SYYBOTT'S MEDIA OPTIMIZER v1.0.31
# Windows PowerShell / WinForms
# ============================================================

$GuiVersion = "1.0.0 Beta 1"
$EngineVersion = "1.0.31"
$CopyWorkerVersion = "1.0.3"
$EmbeddedCopyWorkerBase64 = "__COPY_MODE_WORKER_BASE64__"

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing

[System.Windows.Forms.Application]::EnableVisualStyles()

if (-not ("SyybottThemeCanvas" -as [type])) {
    Add-Type `
        -ReferencedAssemblies @("System.Windows.Forms", "System.Drawing") `
        -TypeDefinition @"
using System.Windows.Forms;

public sealed class SyybottThemeCanvas : Panel
{
    public bool UsesDoubleBuffering
    {
        get { return true; }
    }

    public SyybottThemeCanvas()
    {
        DoubleBuffered = true;
        ResizeRedraw = true;
        SetStyle(
            ControlStyles.AllPaintingInWmPaint |
            ControlStyles.OptimizedDoubleBuffer |
            ControlStyles.UserPaint,
            true
        );
    }
}
"@
}

# The EXE builder replaces this marker with the mascot PNG so Fight Mode stays
# self-contained. Direct PS1 runs load the same image from Assets instead.
$FightMascotBase64 = "__FIGHT_MODE_MASCOT_BASE64__"

function Get-FightMascotImage {
    $imageBytes = $null

    if (-not $FightMascotBase64.StartsWith("__FIGHT_MODE_")) {
        $imageBytes = [System.Convert]::FromBase64String(
            ($FightMascotBase64 -replace '\s', '')
        )
    }
    else {
        $assetPath = Join-Path $ApplicationRoot "Assets\Fight-Mode-Mascot.png"

        if (-not (Test-Path -LiteralPath $assetPath -PathType Leaf)) {
            return $null
        }

        $imageBytes = [System.IO.File]::ReadAllBytes($assetPath)
    }

    $stream = New-Object System.IO.MemoryStream(, $imageBytes)

    try {
        $sourceImage = [System.Drawing.Image]::FromStream($stream)

        try {
            return New-Object System.Drawing.Bitmap($sourceImage)
        }
        finally {
            $sourceImage.Dispose()
        }
    }
    finally {
        $stream.Dispose()
    }
}

$EmbeddedEngineGzipBase64 = @'


'@

function Get-EmbeddedEngineSource {
    $compressedBytes = [System.Convert]::FromBase64String(
        ($EmbeddedEngineGzipBase64 -replace '\s', '')
    )

    $inputStream = New-Object System.IO.MemoryStream(, $compressedBytes)
    $gzipStream = New-Object System.IO.Compression.GzipStream(
        $inputStream,
        [System.IO.Compression.CompressionMode]::Decompress
    )
    $reader = New-Object System.IO.StreamReader(
        $gzipStream,
        [System.Text.Encoding]::UTF8,
        $true
    )

    try {
        return $reader.ReadToEnd().TrimStart([char]0xFEFF)
    }
    finally {
        $reader.Dispose()
        $gzipStream.Dispose()
        $inputStream.Dispose()
    }
}

function Get-EmbeddedCopyWorkerSource {
    if ($EmbeddedCopyWorkerBase64.StartsWith("__COPY_MODE_")) {
        $developmentWorker = Join-Path $ApplicationRoot "SYYBOTTS-Copy-Mode-v1.0.3.ps1"
        if (Test-Path -LiteralPath $developmentWorker -PathType Leaf) {
            return [IO.File]::ReadAllText($developmentWorker).TrimStart([char]0xFEFF)
        }
        throw "The Copy Mode worker is not embedded and its development source is missing."
    }
    $bytes = [Convert]::FromBase64String(
        ($EmbeddedCopyWorkerBase64 -replace '\s', '')
    )
    return [Text.Encoding]::UTF8.GetString($bytes).TrimStart([char]0xFEFF)
}

function Convert-ToPowerShellSingleQuotedLiteral {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Value
    )

    return "'" + $Value.Replace("'", "''") + "'"
}

function Get-RequiredToolPath {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    return Join-Path $ApplicationRoot $Name
}

function Set-ControlTreeEnabled {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$Control,

        [Parameter(Mandatory = $true)]
        [bool]$Enabled
    )

    $Control.Enabled = $Enabled
}

function Show-ErrorMessage {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-DiagnosticLog -Category "ERROR" -Message $Message

    [void][System.Windows.Forms.MessageBox]::Show(
        $Message,
        "SYYBOTT'S Media Optimizer",
        [System.Windows.Forms.MessageBoxButtons]::OK,
        [System.Windows.Forms.MessageBoxIcon]::Error
    )
}

function Show-WarningConfirmation {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [string]$Title = "Permanent file replacement warning"
    )

    if ($script:DisableWarnings) {
        Write-DiagnosticLog `
            -Category "POPUP" `
            -Message "Warning bypassed by saved user setting: $Title"
        return $true
    }

    Write-DiagnosticLog `
        -Category "POPUP" `
        -Message "Opening warning popup: $Title"
    Write-DiagnosticControlSnapshot `
        -Reason "Before warning popup: $Title"

    try {
        $result = [System.Windows.Forms.MessageBox]::Show(
            $Message,
            $Title,
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Warning,
            [System.Windows.Forms.MessageBoxDefaultButton]::Button2
        )
    }
    finally {
        Write-DiagnosticLog `
            -Category "POPUP" `
            -Message "Closed warning popup: $Title; result=$result"
        Write-DiagnosticControlSnapshot `
            -Reason "After warning popup: $Title"
        Write-DiagnosticApplicationState `
            -Reason "After warning popup: $Title"
    }

    return ($result -eq [System.Windows.Forms.DialogResult]::Yes)
}

function Show-DiagnosticInformationMessage {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [Parameter(Mandatory = $true)]
        [string]$Title
    )

    Write-DiagnosticLog `
        -Category "POPUP" `
        -Message "Opening information popup: $Title"
    Write-DiagnosticControlSnapshot `
        -Reason "Before information popup: $Title"

    try {
        [void][System.Windows.Forms.MessageBox]::Show(
            $form,
            $Message,
            $Title,
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Information
        )
    }
    finally {
        Write-DiagnosticLog `
            -Category "POPUP" `
            -Message "Closed information popup: $Title"
        Write-DiagnosticControlSnapshot `
            -Reason "After information popup: $Title"
        Write-DiagnosticApplicationState `
            -Reason "After information popup: $Title"
    }
}

function Confirm-DiagnosticCollection {
    param(
        [string]$Title = "Enable diagnostics"
    )

    $message = @"
Diagnostics records information that helps identify interface and processing problems:

• App, engine, Windows, PowerShell, display, DPI, and screen information
• Control names, text, size, position, visibility, enabled state, fonts, and selected options
• Selected media and Copy Mode destination folder paths
• Theme, tabs, operation modes, tool status, progress, and recent app errors
• A screenshot of the app when a diagnostic package is created

Diagnostics does not copy image or video media files. Folder paths and visible text shown inside the app may appear in the package.

Enable diagnostics?
"@

    $result = [System.Windows.Forms.MessageBox]::Show(
        $form,
        $message,
        $Title,
        [System.Windows.Forms.MessageBoxButtons]::YesNo,
        [System.Windows.Forms.MessageBoxIcon]::Information,
        [System.Windows.Forms.MessageBoxDefaultButton]::Button2
    )

    return ($result -eq [System.Windows.Forms.DialogResult]::Yes)
}

function Get-SavedMediaFolder {
    if (-not (Test-Path -LiteralPath $SettingsPath -PathType Leaf)) {
        return ""
    }

    try {
        $settings = Get-Content `
            -LiteralPath $SettingsPath `
            -Raw `
            -ErrorAction Stop |
            ConvertFrom-Json `
                -ErrorAction Stop

        if ($null -eq $settings -or [string]::IsNullOrWhiteSpace(
            [string]$settings.MediaFolder
        )) {
            return ""
        }

        return [System.IO.Path]::GetFullPath([string]$settings.MediaFolder)
    }
    catch {
        [void][System.Windows.Forms.MessageBox]::Show(
            "The saved media-folder configuration could not be read. Select the folder again to replace it.",
            "Configuration warning",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
        return ""
    }
}

function Get-ApplicationSettings {
    if (-not (Test-Path -LiteralPath $SettingsPath -PathType Leaf)) {
        return [pscustomobject]@{}
    }
    try {
        return Get-Content -LiteralPath $SettingsPath -Raw -ErrorAction Stop |
            ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        return [pscustomobject]@{}
    }
}

function Save-ApplicationSettings {
    param(
        [string]$MediaFolder,
        [string]$CopyDestination,
        [Nullable[bool]]$DiagnosticsEnabled,
        [Nullable[bool]]$AdvancedVideoProfilesEnabled,
        [Nullable[bool]]$DisableWarnings,
        [Nullable[long]]$ModifyFilesProcessed,
        [Nullable[bool]]$FightModeDiscovered
    )
    try {
        [void](New-Item -ItemType Directory -Path $ConfigurationFolder -Force)
        $current = Get-ApplicationSettings
        $settings = [ordered]@{
            MediaFolder = if ([string]::IsNullOrWhiteSpace($MediaFolder)) {
                [string]$current.MediaFolder
            } else { [IO.Path]::GetFullPath($MediaFolder) }
            CopyDestination = if ([string]::IsNullOrWhiteSpace($CopyDestination)) {
                [string]$current.CopyDestination
            } else { [IO.Path]::GetFullPath($CopyDestination) }
            DiagnosticsEnabled = if ($null -eq $DiagnosticsEnabled) {
                [bool]$current.DiagnosticsEnabled
            } else {
                [bool]$DiagnosticsEnabled
            }
            AdvancedVideoProfilesEnabled = if (
                $null -eq $AdvancedVideoProfilesEnabled
            ) {
                [bool]$current.AdvancedVideoProfilesEnabled
            } else {
                [bool]$AdvancedVideoProfilesEnabled
            }
            DisableWarnings = if ($null -eq $DisableWarnings) {
                [bool]$current.DisableWarnings
            } else {
                [bool]$DisableWarnings
            }
            ModifyFilesProcessed = if ($null -eq $ModifyFilesProcessed) {
                [long]$current.ModifyFilesProcessed
            } else {
                [long]$ModifyFilesProcessed
            }
            FightModeDiscovered = if ($null -eq $FightModeDiscovered) {
                [bool]$current.FightModeDiscovered
            } else {
                [bool]$FightModeDiscovered
            }
        }
        $settings | ConvertTo-Json | Set-Content -LiteralPath $SettingsPath -Encoding UTF8
        return $true
    }
    catch {
        [void][Windows.Forms.MessageBox]::Show(
            "The application settings could not be saved.`r`n`r`n$($_.Exception.Message)",
            "Configuration warning",
            [Windows.Forms.MessageBoxButtons]::OK,
            [Windows.Forms.MessageBoxIcon]::Warning
        )
        return $false
    }
}

function Save-MediaFolderSetting {
    param(
        [Parameter(Mandatory = $true)]
        [string]$MediaFolder
    )

    try {
        $fullMediaFolder = [System.IO.Path]::GetFullPath($MediaFolder)

        [void](New-Item `
            -ItemType Directory `
            -Path $ConfigurationFolder `
            -Force `
            -ErrorAction Stop)

        return (Save-ApplicationSettings -MediaFolder $fullMediaFolder)
    }
    catch {
        [void][System.Windows.Forms.MessageBox]::Show(
            "The media folder could not be saved in Configuration\settings.json.`r`n`r`n$($_.Exception.Message)",
            "Configuration warning",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
        return $false
    }
}

function Select-MediaFolderAndSave {
    [void][System.Windows.Forms.MessageBox]::Show(
        "Select the main media folder used by the optimizer.`r`n`r`nWindows ES-DE users should normally select:`r`nES-DE\ES-DE\downloaded_media",
        "Select media folder",
        [System.Windows.Forms.MessageBoxButtons]::OK,
        [System.Windows.Forms.MessageBoxIcon]::Information
    )

    $dialog = New-Object System.Windows.Forms.FolderBrowserDialog
    $dialog.Description = "Select the main image and video media folder"
    $dialog.ShowNewFolderButton = $false

    if (
        $null -ne $folderTextBox -and
        (Test-Path -LiteralPath $folderTextBox.Text -PathType Container)
    ) {
        $dialog.SelectedPath = $folderTextBox.Text
    }

    try {
        if (
            $dialog.ShowDialog($form) -ne
            [System.Windows.Forms.DialogResult]::OK
        ) {
            return $false
        }

        $selectedFolder = [System.IO.Path]::GetFullPath(
            $dialog.SelectedPath
        )
        $folderTextBox.Text = $selectedFolder
        [void](Save-MediaFolderSetting -MediaFolder $selectedFolder)
        return $true
    }
    finally {
        $dialog.Dispose()
    }
}

function Ensure-MediaFolderConfigured {
    $savedFolder = Get-SavedMediaFolder

    if (-not [string]::IsNullOrWhiteSpace($savedFolder)) {
        if (Test-Path -LiteralPath $savedFolder -PathType Container) {
            $folderTextBox.Text = $savedFolder
            return $true
        }

        [void][System.Windows.Forms.MessageBox]::Show(
            "The saved media folder no longer exists. Select its current location.",
            "Media folder not found",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Warning
        )
    }

    return Select-MediaFolderAndSave
}

function Initialize-DiagnosticSession {
    param([switch]$Force)

    if (-not $script:DiagnosticsEnabled -and -not $Force) {
        return $false
    }

    try {
        [void](New-Item `
            -ItemType Directory `
            -Path $DiagnosticsFolder `
            -Force `
            -ErrorAction Stop)

        if ([string]::IsNullOrWhiteSpace($script:DiagnosticSessionId)) {
            $script:DiagnosticSessionId = (
                Get-Date -Format "yyyyMMdd-HHmmss-fff"
            )
        }

        if ([string]::IsNullOrWhiteSpace($script:DiagnosticLogPath)) {
            $script:DiagnosticLogPath = Join-Path (
                $DiagnosticsFolder
            ) "SYYBOTTS-Diagnostics-$($script:DiagnosticSessionId).txt"
        }

        if ([string]::IsNullOrWhiteSpace($script:DiagnosticLayoutPath)) {
            $script:DiagnosticLayoutPath = Join-Path (
                $DiagnosticsFolder
            ) "SYYBOTTS-Control-Layout-$($script:DiagnosticSessionId).jsonl"
        }

        if (-not (Test-Path -LiteralPath $script:DiagnosticLogPath)) {
            @(
                "SYYBOTT'S MEDIA OPTIMIZER DIAGNOSTICS"
                "Session: $($script:DiagnosticSessionId)"
                "Application version: $GuiVersion"
                "Engine version: $EngineVersion"
                "Copy worker version: $CopyWorkerVersion"
                "Started: $([DateTime]::Now.ToString('o'))"
                ""
            ) | Set-Content `
                -LiteralPath $script:DiagnosticLogPath `
                -Encoding UTF8 `
                -ErrorAction Stop
        }

        return $true
    }
    catch {
        return $false
    }
}

function Write-DiagnosticLog {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [string]$Category = "INFO",

        [switch]$Force
    )

    if (
        (-not $script:DiagnosticsEnabled -and -not $Force) -or
        $script:DiagnosticWriteInProgress
    ) {
        return
    }

    $script:DiagnosticWriteInProgress = $true

    try {
        if (-not (Initialize-DiagnosticSession -Force:$Force)) {
            return
        }

        $line = "{0} [{1}] {2}" -f (
            [DateTime]::Now.ToString("o"),
            $Category.ToUpperInvariant(),
            $Message
        )

        Add-Content `
            -LiteralPath $script:DiagnosticLogPath `
            -Value $line `
            -Encoding UTF8 `
            -ErrorAction Stop
    }
    catch {
        # Diagnostic logging must never interrupt the optimizer.
    }
    finally {
        $script:DiagnosticWriteInProgress = $false
    }
}

function Write-DiagnosticException {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Source,

        [System.Exception]$Exception
    )

    if ($null -eq $Exception) {
        Write-DiagnosticLog `
            -Category "ERROR" `
            -Message "$Source reported an unknown exception."
        return
    }

    $details = @(
        "Source: $Source"
        "Type: $($Exception.GetType().FullName)"
        "Message: $($Exception.Message)"
        "Stack: $($Exception.StackTrace)"
    ) -join " | "

    Write-DiagnosticLog -Category "ERROR" -Message $details
}

function Get-DiagnosticControlRecords {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$RootControl
    )

    $records = New-Object System.Collections.Generic.List[object]
    $pending = New-Object System.Collections.Stack
    $pending.Push(
        [pscustomobject]@{
            Control = $RootControl
            ParentPath = ""
            Index = 0
        }
    )

    while ($pending.Count -gt 0) {
        $item = $pending.Pop()
        $control = [System.Windows.Forms.Control]$item.Control
        $typeName = $control.GetType().FullName
        $shortType = $control.GetType().Name
        $controlName = if ([string]::IsNullOrWhiteSpace($control.Name)) {
            "$shortType[$($item.Index)]"
        } else {
            $control.Name
        }
        $controlPath = if ([string]::IsNullOrWhiteSpace($item.ParentPath)) {
            $controlName
        } else {
            "$($item.ParentPath)/$controlName"
        }

        try {
            $screenPoint = $control.PointToScreen(
                [System.Drawing.Point]::Empty
            )
            $screenBounds = [ordered]@{
                X = $screenPoint.X
                Y = $screenPoint.Y
                Width = $control.Width
                Height = $control.Height
            }
        }
        catch {
            $screenBounds = $null
        }

        $text = ""
        try {
            $text = [string]$control.Text
            if ($text.Length -gt 300) {
                $text = $text.Substring(0, 300)
            }
        }
        catch {
            $text = ""
        }

        $parentControl = $control.Parent
        $parentClientWidth = $null
        $parentClientHeight = $null
        $parentDisplayX = $null
        $parentDisplayY = $null
        $parentDisplayWidth = $null
        $parentDisplayHeight = $null
        $parentAutoScroll = $false

        if ($null -ne $parentControl) {
            $parentClientWidth = $parentControl.ClientSize.Width
            $parentClientHeight = $parentControl.ClientSize.Height
            $displayRectangle = $parentControl.DisplayRectangle
            $parentDisplayX = $displayRectangle.X
            $parentDisplayY = $displayRectangle.Y
            $parentDisplayWidth = $displayRectangle.Width
            $parentDisplayHeight = $displayRectangle.Height

            if ($parentControl -is [System.Windows.Forms.ScrollableControl]) {
                $parentAutoScroll = $parentControl.AutoScroll
            }
        }

        $records.Add(
            [pscustomobject][ordered]@{
                Path = $controlPath
                Name = $controlName
                Type = $typeName
                Parent = $item.ParentPath
                Text = $text
                X = $control.Left
                Y = $control.Top
                Width = $control.Width
                Height = $control.Height
                Right = $control.Left + $control.Width
                Bottom = $control.Top + $control.Height
                ClientWidth = $control.ClientSize.Width
                ClientHeight = $control.ClientSize.Height
                ParentClientWidth = $parentClientWidth
                ParentClientHeight = $parentClientHeight
                ParentDisplayX = $parentDisplayX
                ParentDisplayY = $parentDisplayY
                ParentDisplayWidth = $parentDisplayWidth
                ParentDisplayHeight = $parentDisplayHeight
                ParentAutoScroll = $parentAutoScroll
                ScreenBounds = $screenBounds
                Visible = $control.Visible
                Enabled = $control.Enabled
                InternalWinFormsChild = (
                    Test-IsInternalWinFormsChildControl -Control $control
                )
                Anchor = [string]$control.Anchor
                Dock = [string]$control.Dock
                FontFamily = $control.Font.FontFamily.Name
                FontPoints = [math]::Round(
                    [double]$control.Font.SizeInPoints,
                    2
                )
                AutoSize = $control.AutoSize
                TabIndex = $control.TabIndex
            }
        )

        for (
            $childIndex = $control.Controls.Count - 1;
            $childIndex -ge 0;
            $childIndex--
        ) {
            $pending.Push(
                [pscustomobject]@{
                    Control = $control.Controls[$childIndex]
                    ParentPath = $controlPath
                    Index = $childIndex
                }
            )
        }
    }

    return $records.ToArray()
}

function Get-DiagnosticLayoutIssues {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$RootControl,

        [switch]$IncludeHidden
    )

    $issues = New-Object System.Collections.Generic.List[object]
    $records = @(Get-DiagnosticControlRecords -RootControl $RootControl)

    foreach ($record in $records) {
        if (
            $record.Path -eq $records[0].Path -or
            $record.InternalWinFormsChild -or
            (-not $IncludeHidden -and -not $record.Visible)
        ) {
            continue
        }

        $reason = ""

        if ($record.Width -le 0 -or $record.Height -le 0) {
            $reason = "Control has a zero or negative size."
        }
        elseif (
            $null -ne $record.ParentClientWidth -and
            -not $record.ParentAutoScroll -and
            (
                $record.Right -le 0 -or
                $record.Bottom -le 0
            )
        ) {
            $reason = "Control is completely outside its parent viewport."
        }
        elseif (
            $null -ne $record.ParentClientWidth -and
            -not $record.ParentAutoScroll -and
            (
                $record.X -lt 0 -or
                $record.Y -lt 0 -or
                $record.Right -gt ($record.ParentClientWidth + 2) -or
                $record.Bottom -gt ($record.ParentClientHeight + 2)
            )
        ) {
            $reason = "Control extends beyond its parent client area."
        }

        if (-not [string]::IsNullOrWhiteSpace($reason)) {
            [void]$issues.Add(
                [pscustomobject][ordered]@{
                    Path = $record.Path
                    Type = $record.Type
                    Parent = $record.Parent
                    X = $record.X
                    Y = $record.Y
                    Width = $record.Width
                    Height = $record.Height
                    Right = $record.Right
                    Bottom = $record.Bottom
                    ParentClientWidth = $record.ParentClientWidth
                    ParentClientHeight = $record.ParentClientHeight
                    Reason = $reason
                }
            )
        }
    }

    return $issues.ToArray()
}

function Write-DiagnosticControlSnapshot {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Reason,

        [System.Windows.Forms.Control]$RootControl = $form
    )

    if (-not $script:DiagnosticsEnabled -or $null -eq $RootControl) {
        return
    }

    try {
        if (-not (Initialize-DiagnosticSession)) {
            return
        }

        $records = @(Get-DiagnosticControlRecords -RootControl $RootControl)
        $snapshot = [pscustomobject][ordered]@{
            Timestamp = [DateTime]::Now.ToString("o")
            Reason = $Reason
            RootType = $RootControl.GetType().FullName
            RootText = [string]$RootControl.Text
            ControlCount = $records.Count
            Controls = $records
        }

        $json = $snapshot | ConvertTo-Json -Depth 8 -Compress
        Add-Content `
            -LiteralPath $script:DiagnosticLayoutPath `
            -Value $json `
            -Encoding UTF8 `
            -ErrorAction Stop

        Write-DiagnosticLog `
            -Category "LAYOUT" `
            -Message "$Reason; captured $($records.Count) controls."
    }
    catch {
        Write-DiagnosticException `
            -Source "Control layout snapshot: $Reason" `
            -Exception $_.Exception
    }
}

function Get-DiagnosticApplicationState {
    $screen = $null
    $dpiX = $null
    $dpiY = $null
    $graphics = $null

    try {
        if ($null -ne $form) {
            $screen = [System.Windows.Forms.Screen]::FromControl($form)
            $graphics = $form.CreateGraphics()
            $dpiX = $graphics.DpiX
            $dpiY = $graphics.DpiY
        }
    }
    catch {
        $screen = $null
    }
    finally {
        if ($null -ne $graphics) {
            $graphics.Dispose()
        }
    }

    $recentErrors = @(
        $global:Error |
            Select-Object -First 20 |
            ForEach-Object {
                [pscustomobject]@{
                    Message = $_.ToString()
                    ScriptStackTrace = [string]$_.ScriptStackTrace
                }
            }
    )

    return [pscustomobject][ordered]@{
        Captured = [DateTime]::Now.ToString("o")
        ApplicationVersion = $GuiVersion
        EngineVersion = $EngineVersion
        CopyWorkerVersion = $CopyWorkerVersion
        Windows = [Environment]::OSVersion.VersionString
        PowerShell = [string]$PSVersionTable.PSVersion
        DotNet = [string][Environment]::Version
        Is64BitProcess = [Environment]::Is64BitProcess
        ApplicationRoot = $ApplicationRoot
        SettingsPath = $SettingsPath
        DiagnosticsEnabled = $script:DiagnosticsEnabled
        AdvancedVideoProfilesEnabled = (
            $script:AdvancedVideoProfilesEnabled
        )
        DisableWarnings = $script:DisableWarnings
        ModifyFilesProcessed = $script:ModifyFilesProcessed
        FightModeDiscovered = $script:FightModeDiscovered
        DiagnosticLogPath = $script:DiagnosticLogPath
        Theme = $script:CurrentTheme
        DisplayScaleFactor = $script:DisplayScaleFactor
        DpiX = $dpiX
        DpiY = $dpiY
        Screen = if ($null -eq $screen) {
            $null
        } else {
            [ordered]@{
                DeviceName = $screen.DeviceName
                Bounds = [ordered]@{
                    X = $screen.Bounds.X
                    Y = $screen.Bounds.Y
                    Width = $screen.Bounds.Width
                    Height = $screen.Bounds.Height
                }
                WorkingArea = [ordered]@{
                    X = $screen.WorkingArea.X
                    Y = $screen.WorkingArea.Y
                    Width = $screen.WorkingArea.Width
                    Height = $screen.WorkingArea.Height
                }
                Primary = $screen.Primary
            }
        }
        Form = if ($null -eq $form) {
            $null
        } else {
            [ordered]@{
                X = $form.Left
                Y = $form.Top
                Width = $form.Width
                Height = $form.Height
                ClientWidth = $form.ClientSize.Width
                ClientHeight = $form.ClientSize.Height
                WindowState = [string]$form.WindowState
                Visible = $form.Visible
            }
        }
        SelectedTab = if ($null -eq $tabControl) {
            $null
        } else {
            $tabControl.SelectedIndex
        }
        ImageOperation = if ($null -eq $imageOperationCombo) {
            $null
        } else {
            [string]$imageOperationCombo.Tag
        }
        VideoOperation = if ($null -eq $videoOperationCombo) {
            $null
        } else {
            [string]$videoOperationCombo.Tag
        }
        JpegHandling = if ($null -eq $jpegHandlingCombo) {
            $null
        } else {
            [string]$jpegHandlingCombo.SelectedItem
        }
        PngHandling = if ($null -eq $pngHandlingCombo) {
            $null
        } else {
            [string]$pngHandlingCombo.SelectedItem
        }
        ImageTestEnabled = if ($null -eq $imageTestCheckBox) {
            $null
        } else {
            $imageTestCheckBox.Checked
        }
        VideoTestEnabled = if ($null -eq $videoTestCheckBox) {
            $null
        } else {
            $videoTestCheckBox.Checked
        }
        MediaFolder = if ($null -eq $folderTextBox) {
            $null
        } else {
            $folderTextBox.Text
        }
        CopyDestination = if ($null -eq $copyDestinationTextBox) {
            $null
        } else {
            $copyDestinationTextBox.Text
        }
        CurrentOperation = $script:CurrentOperation
        ToolStatus = if ($null -eq $cwebpStatusLabel) {
            $null
        } else {
            @(
                $cwebpStatusLabel.Text
                $ffmpegStatusLabel.Text
                $ffprobeStatusLabel.Text
            )
        }
        RecentPowerShellErrors = $recentErrors
    }
}

function Write-DiagnosticApplicationState {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Reason
    )

    if (-not $script:DiagnosticsEnabled) {
        return
    }

    try {
        $state = Get-DiagnosticApplicationState
        $stateJson = $state | ConvertTo-Json -Depth 8 -Compress
        Write-DiagnosticLog `
            -Category "STATE" `
            -Message "$Reason | $stateJson"
    }
    catch {
        Write-DiagnosticException `
            -Source "Application state: $Reason" `
            -Exception $_.Exception
    }
}

function New-DiagnosticPackage {
    param(
        [switch]$ShowConfirmation,
        [string]$AdditionalReportPath
    )

    $stagingFolder = $null

    try {
        if (-not (Initialize-DiagnosticSession -Force)) {
            throw "The diagnostics folder could not be created."
        }

        Write-DiagnosticLog `
            -Force `
            -Category "PACKAGE" `
            -Message "Diagnostic package capture requested."

        $packageId = Get-Date -Format "yyyyMMdd-HHmmss-fff"
        $stagingFolder = Join-Path (
            [IO.Path]::GetTempPath()
        ) "SYYBOTTS-Diagnostics-$packageId"
        [void](New-Item `
            -ItemType Directory `
            -Path $stagingFolder `
            -Force `
            -ErrorAction Stop)

        $state = Get-DiagnosticApplicationState
        $state |
            ConvertTo-Json -Depth 10 |
            Set-Content `
                -LiteralPath (
                    Join-Path $stagingFolder "Application-State.json"
                ) `
                -Encoding UTF8 `
                -ErrorAction Stop

        if ($null -ne $form) {
            @(Get-DiagnosticControlRecords -RootControl $form) |
                ConvertTo-Json -Depth 8 |
                Set-Content `
                    -LiteralPath (
                        Join-Path $stagingFolder "Current-Control-Layout.json"
                    ) `
                    -Encoding UTF8 `
                    -ErrorAction Stop

            try {
                $bitmap = New-Object System.Drawing.Bitmap(
                    [math]::Max(1, $form.Width),
                    [math]::Max(1, $form.Height)
                )
                $rectangle = New-Object System.Drawing.Rectangle(
                    0,
                    0,
                    $bitmap.Width,
                    $bitmap.Height
                )
                $form.DrawToBitmap($bitmap, $rectangle)
                $bitmap.Save(
                    (Join-Path $stagingFolder "Application-Screenshot.png"),
                    [System.Drawing.Imaging.ImageFormat]::Png
                )
                $bitmap.Dispose()
            }
            catch {
                if ($null -ne $bitmap) {
                    $bitmap.Dispose()
                }
                Write-DiagnosticException `
                    -Source "Application screenshot" `
                    -Exception $_.Exception
            }
        }

        if (
            -not [string]::IsNullOrWhiteSpace($script:DiagnosticLogPath) -and
            (Test-Path -LiteralPath $script:DiagnosticLogPath -PathType Leaf)
        ) {
            Copy-Item `
                -LiteralPath $script:DiagnosticLogPath `
                -Destination (
                    Join-Path $stagingFolder "Diagnostic-Log.txt"
                ) `
                -Force `
                -ErrorAction Stop
        }

        if (
            -not [string]::IsNullOrWhiteSpace(
                $script:DiagnosticLayoutPath
            ) -and
            (
                Test-Path `
                    -LiteralPath $script:DiagnosticLayoutPath `
                    -PathType Leaf
            )
        ) {
            Copy-Item `
                -LiteralPath $script:DiagnosticLayoutPath `
                -Destination (
                    Join-Path $stagingFolder "Control-Layout-History.jsonl"
                ) `
                -Force `
                -ErrorAction Stop
        }

        if (
            -not [string]::IsNullOrWhiteSpace($AdditionalReportPath) -and
            (Test-Path -LiteralPath $AdditionalReportPath -PathType Leaf)
        ) {
            Copy-Item `
                -LiteralPath $AdditionalReportPath `
                -Destination (
                    Join-Path $stagingFolder (
                        Split-Path -Leaf $AdditionalReportPath
                    )
                ) `
                -Force `
                -ErrorAction Stop
        }

        @(
            "SYYBOTT'S Media Optimizer diagnostic package"
            ""
            "This package contains application state, control layout,"
            "diagnostic events, and an application screenshot."
            ""
            "It does not contain image or video media files."
            "Selected folder paths may be present because they help diagnose"
            "folder and layout problems."
        ) | Set-Content `
            -LiteralPath (Join-Path $stagingFolder "README.txt") `
            -Encoding UTF8 `
            -ErrorAction Stop

        Add-Type -AssemblyName System.IO.Compression.FileSystem
        $packagePath = Join-Path (
            $DiagnosticsFolder
        ) "SYYBOTTS-Diagnostic-Package-$packageId.zip"
        if (Test-Path -LiteralPath $packagePath) {
            Remove-Item -LiteralPath $packagePath -Force
        }
        [IO.Compression.ZipFile]::CreateFromDirectory(
            $stagingFolder,
            $packagePath,
            [IO.Compression.CompressionLevel]::Optimal,
            $false
        )

        $script:LastDiagnosticPackagePath = $packagePath
        Write-DiagnosticLog `
            -Force `
            -Category "PACKAGE" `
            -Message "Created diagnostic package: $packagePath"

        if ($ShowConfirmation) {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                (
                    "Diagnostic package created in Logs\Diagnostics " +
                    "beside the app:`r`n`r`n$packagePath"
                ),
                "Diagnostic package",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )
        }

        return $packagePath
    }
    catch {
        Write-DiagnosticException `
            -Source "Diagnostic package creation" `
            -Exception $_.Exception

        if ($ShowConfirmation) {
            [void][System.Windows.Forms.MessageBox]::Show(
                $form,
                "The diagnostic package could not be created.`r`n`r`n$($_.Exception.Message)",
                "Diagnostic package error",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Error
            )
        }

        return $null
    }
    finally {
        if (
            -not [string]::IsNullOrWhiteSpace($stagingFolder) -and
            (Test-Path -LiteralPath $stagingFolder)
        ) {
            Remove-Item `
                -LiteralPath $stagingFolder `
                -Recurse `
                -Force `
                -ErrorAction SilentlyContinue
        }
    }
}

