if (-not ("SyybottPowerState" -as [type])) {
    Add-Type @"
using System;
using System.Runtime.InteropServices;

public static class SyybottPowerState
{
    [DllImport("kernel32.dll", SetLastError = true)]
    public static extern uint SetThreadExecutionState(uint executionState);
}
"@
}

function Enable-SleepPrevention {
    [uint32]$result = [SyybottPowerState]::SetThreadExecutionState(
        [uint32]2147483649
    )

    if ($result -eq 0) {
        return $false
    }

    $script:SleepPreventionActive = $true
    return $true
}

function Disable-SleepPrevention {
    if (-not $script:SleepPreventionActive) {
        return
    }

    [void][SyybottPowerState]::SetThreadExecutionState(
        [uint32]2147483648
    )
    $script:SleepPreventionActive = $false
}

