function Test-WarningDisableUnlocked {
    return (
        $script:FightModeDiscovered -or
        $script:ModifyFilesProcessed -ge $script:WarningUnlockThreshold
    )
}

function Update-WarningControls {
    $unlocked = Test-WarningDisableUnlocked
    $disableWarningsCheckBox.Enabled = $unlocked

    if (-not $unlocked) {
        $script:SuppressWarningToggle = $true
        try {
            $disableWarningsCheckBox.Checked = $false
        }
        finally {
            $script:SuppressWarningToggle = $false
        }
        $script:DisableWarnings = $false
        $warningsUnlockLabel.Text = (
            "Unlocked after $($script:WarningUnlockThreshold) Modify files."
        )
    }
    else {
        $warningsUnlockLabel.Text = ""
    }
}

function Save-ModifyProgress {
    param([switch]$Force)

    if (-not $script:CurrentRunCountsModify) {
        return
    }

    if (
        -not $Force -and
        (
            $script:CurrentModifyRunMaximum -
            $script:LastSavedModifyRunMaximum
        ) -lt 100
    ) {
        return
    }

    $delta = (
        $script:CurrentModifyRunMaximum -
        $script:LastSavedModifyRunMaximum
    )
    if ($delta -gt 0) {
        $script:ModifyFilesProcessed += [long]$delta
        $script:LastSavedModifyRunMaximum = (
            $script:CurrentModifyRunMaximum
        )
        [void](Save-ApplicationSettings `
            -ModifyFilesProcessed $script:ModifyFilesProcessed)
        Update-WarningControls
    }
}

function Set-ImageOptimizationPreset {
    param(
        [Parameter(Mandatory = $true)]
        [ValidateSet("Default", "SuperLight")]
        [string]$Preset
    )

    $script:SuppressPngCompressionNotice = $true
    try {
        $pngCompressionNumeric.Value = 10
        $jpegQualityNumeric.Value = if ($Preset -eq "SuperLight") {
            10
        } else {
            90
        }
    }
    finally {
        $script:SuppressPngCompressionNotice = $false
        $script:LastPngCompressionValue = 10
    }
}

