function Update-VideoProfileChoices {
    $videoProfileCombo.BeginUpdate()
    $videoTestCombo.BeginUpdate()

    try {
        $videoProfileCombo.Items.Clear()
        $videoTestCombo.Items.Clear()

        if ($script:AdvancedVideoProfilesEnabled) {
            $profileItems = @(
                "H.264 CRF 20 / AAC 160k",
                "H.264 CRF 22 / AAC 128k",
                "Default - CRF 24 / AAC 96k",
                "H.264 CRF 25 / AAC 88k",
                "H.264 CRF 26 / AAC 80k",
                "H.264 CRF 27 / AAC 72k",
                "Super Light - CRF 28 / AAC 64k"
            )
            $script:VideoProfileChoices = @(1, 2, 3, 4, 5, 6, 7)
            $selectedProfileIndex = 2

            $testItems = @(
                "Select encoding",
                "H.264 CRF 20 / AAC 160k + Balanced",
                "H.264 CRF 20 / AAC 160k + Maximum Compression",
                "H.264 CRF 22 / AAC 128k + Balanced",
                "H.264 CRF 22 / AAC 128k + Maximum Compression",
                "H.264 CRF 25 / AAC 88k + Balanced",
                "H.264 CRF 25 / AAC 88k + Maximum Compression",
                "H.264 CRF 26 / AAC 80k + Balanced",
                "H.264 CRF 26 / AAC 80k + Maximum Compression",
                "H.264 CRF 27 / AAC 72k + Balanced",
                "H.264 CRF 27 / AAC 72k + Maximum Compression"
            )
            $script:VideoTestChoices = @(0, 1, 2, 3, 4, 7, 8, 9, 10, 11, 12)
            $selectedTestIndex = 0
        }
        else {
            $profileItems = @(
                "Default - CRF 24 / AAC 96k",
                "Super Light - CRF 28 / AAC 64k"
            )
            $script:VideoProfileChoices = @(3, 7)
            $selectedProfileIndex = 0

            $testItems = @(
                "Standard test: four comparisons"
            )
            $script:VideoTestChoices = @(0)
            $selectedTestIndex = 0
        }

        foreach ($item in $profileItems) {
            [void]$videoProfileCombo.Items.Add($item)
        }
        foreach ($item in $testItems) {
            [void]$videoTestCombo.Items.Add($item)
        }

        $videoProfileCombo.SelectedIndex = $selectedProfileIndex
        $videoTestCombo.SelectedIndex = $selectedTestIndex
        $videoTestCombo.Enabled = (
            $videoTestCheckBox.Checked -and
            $script:AdvancedVideoProfilesEnabled
        )
    }
    finally {
        $videoProfileCombo.EndUpdate()
        $videoTestCombo.EndUpdate()
    }
}

function Get-SelectedVideoProfileChoice {
    if (
        $videoProfileCombo.SelectedIndex -lt 0 -or
        $videoProfileCombo.SelectedIndex -ge $script:VideoProfileChoices.Count
    ) {
        return 3
    }

    return [int]$script:VideoProfileChoices[$videoProfileCombo.SelectedIndex]
}

function Get-SelectedVideoTestChoice {
    if (
        $videoTestCombo.SelectedIndex -lt 0 -or
        $videoTestCombo.SelectedIndex -ge $script:VideoTestChoices.Count
    ) {
        return 0
    }

    return [int]$script:VideoTestChoices[$videoTestCombo.SelectedIndex]
}

function Get-SelectedVideoTestPlan {
    if ($script:AdvancedVideoProfilesEnabled) {
        $selectedChoice = Get-SelectedVideoTestChoice
        return $(if ($selectedChoice -gt 0) {
            [string]$selectedChoice
        } else {
            ""
        })
    }

    return "5,6,13,14"
}

