function Test-IsInternalWinFormsChildControl {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$Control
    )

    return (
        $Control.GetType().FullName -in @(
            "System.Windows.Forms.UpDownBase+UpDownButtons",
            "System.Windows.Forms.UpDownBase+UpDownEdit"
        ) -or
        $Control -is [System.Windows.Forms.HScrollBar] -or
        $Control -is [System.Windows.Forms.VScrollBar]
    )
}

function Scale-ControlTreeOnce {
    param(
        [Parameter(Mandatory = $true)]
        [System.Windows.Forms.Control]$RootControl,

        [Parameter(Mandatory = $true)]
        [double]$ScaleFactor
    )

    if ($ScaleFactor -le 1.01) {
        return
    }

    $pendingControls = New-Object System.Collections.Stack
    $snapshots = New-Object System.Collections.Generic.List[object]

    foreach ($childControl in $RootControl.Controls) {
        $pendingControls.Push($childControl)
    }

    while ($pendingControls.Count -gt 0) {
        $control = [System.Windows.Forms.Control]$pendingControls.Pop()

        foreach ($childControl in $control.Controls) {
            $pendingControls.Push($childControl)
        }

        if (Test-IsInternalWinFormsChildControl -Control $control) {
            continue
        }

        $snapshots.Add(
            [pscustomobject]@{
                Control = $control
                Bounds = $control.Bounds
                Anchor = $control.Anchor
                FontFamily = $control.Font.FontFamily
                SizeInPoints = [double]$control.Font.SizeInPoints
                Style = $control.Font.Style
            }
        )
    }

    $rootClientSize = $RootControl.ClientSize
    $rootMinimumSize = if ($RootControl -is [System.Windows.Forms.Form]) {
        $RootControl.MinimumSize
    }
    else {
        [System.Drawing.Size]::Empty
    }
    $rootFontFamily = $RootControl.Font.FontFamily
    $rootFontSize = [double]$RootControl.Font.SizeInPoints
    $rootFontStyle = $RootControl.Font.Style

    $RootControl.SuspendLayout()

    try {
        # Anchors are temporarily disabled so resizing a parent cannot also
        # stretch or reposition a child before its captured bounds are applied.
        foreach ($snapshot in $snapshots) {
            $snapshot.Control.Anchor = [System.Windows.Forms.AnchorStyles]::Top `
                -bor [System.Windows.Forms.AnchorStyles]::Left
        }

        $RootControl.ClientSize = New-Object System.Drawing.Size(
            [int][math]::Round($rootClientSize.Width * $ScaleFactor),
            [int][math]::Round($rootClientSize.Height * $ScaleFactor)
        )

        foreach ($snapshot in $snapshots) {
            $bounds = $snapshot.Bounds
            $snapshot.Control.SetBounds(
                [int][math]::Round($bounds.X * $ScaleFactor),
                [int][math]::Round($bounds.Y * $ScaleFactor),
                [int][math]::Round($bounds.Width * $ScaleFactor),
                [int][math]::Round($bounds.Height * $ScaleFactor)
            )
        }

        $RootControl.Font = New-Object System.Drawing.Font(
            $rootFontFamily,
            [single][math]::Max(7.0, $rootFontSize * $ScaleFactor),
            $rootFontStyle,
            [System.Drawing.GraphicsUnit]::Point
        )

        # Font snapshots were captured before any parent font changed. Each
        # control therefore receives exactly one font scale pass.
        for ($index = $snapshots.Count - 1; $index -ge 0; $index--) {
            $snapshot = $snapshots[$index]
            $snapshot.Control.Font = New-Object System.Drawing.Font(
                $snapshot.FontFamily,
                [single][math]::Max(
                    7.0,
                    $snapshot.SizeInPoints * $ScaleFactor
                ),
                $snapshot.Style,
                [System.Drawing.GraphicsUnit]::Point
            )
        }

        if (
            $RootControl -is [System.Windows.Forms.Form] -and
            -not $rootMinimumSize.IsEmpty
        ) {
            $RootControl.MinimumSize = New-Object System.Drawing.Size(
                [int][math]::Round(
                    $rootMinimumSize.Width * $ScaleFactor
                ),
                [int][math]::Round(
                    $rootMinimumSize.Height * $ScaleFactor
                )
            )
        }

    }
    finally {
        $RootControl.ResumeLayout($true)
    }

    # Parent layout can adjust anchored children during the first resume.
    # Reapply each captured, scaled rectangle once, then restore anchors.
    $RootControl.SuspendLayout()
    try {
        foreach ($snapshot in $snapshots) {
            if ($snapshot.Control.Dock -eq [System.Windows.Forms.DockStyle]::None) {
                $bounds = $snapshot.Bounds
                $snapshot.Control.SetBounds(
                    [int][math]::Round($bounds.X * $ScaleFactor),
                    [int][math]::Round($bounds.Y * $ScaleFactor),
                    [int][math]::Round($bounds.Width * $ScaleFactor),
                    [int][math]::Round($bounds.Height * $ScaleFactor)
                )
            }
        }
        foreach ($snapshot in $snapshots) {
            $snapshot.Control.Anchor = $snapshot.Anchor
        }
    }
    finally {
        $RootControl.ResumeLayout($false)
    }
}

function Initialize-DisplayScaling {
    if ($script:DisplayScaleApplied) {
        return
    }

    $script:DisplayScaleApplied = $true

    $graphics = $null

    try {
        $graphics = $form.CreateGraphics()
        [double]$dpiScale = $graphics.DpiX / 96.0
    }
    catch {
        [double]$dpiScale = 1.0
    }
    finally {
        if ($null -ne $graphics) {
            $graphics.Dispose()
        }
    }

    $targetScreen = [System.Windows.Forms.Screen]::FromPoint(
        [System.Windows.Forms.Cursor]::Position
    )
    $workingArea = $targetScreen.WorkingArea

    [double]$scaleFactor = [math]::Max(1.0, $dpiScale)

    # A 4K panel at 100% Windows scaling still needs a larger application UI.
    if ($workingArea.Width -ge 3000 -and $scaleFactor -lt 1.5) {
        $scaleFactor = 1.5
    }
    elseif ($workingArea.Width -ge 2400 -and $scaleFactor -lt 1.25) {
        $scaleFactor = 1.25
    }

    # Keep the complete window visible on smaller displays or unusually high
    # Windows scaling settings.
    $horizontalFit = ($workingArea.Width - 80.0) / $form.Width
    $verticalFit = ($workingArea.Height - 80.0) / $form.Height
    $maximumFit = [math]::Min($horizontalFit, $verticalFit)

    if ($maximumFit -gt 0) {
        $scaleFactor = [math]::Min($scaleFactor, $maximumFit)
    }

    $scaleFactor = [math]::Min(2.0, [math]::Max(1.0, $scaleFactor))
    $scaleFactor = [math]::Round($scaleFactor * 20.0) / 20.0
    $script:DisplayScaleFactor = $scaleFactor

    if ($scaleFactor -gt 1.01) {
        Scale-ControlTreeOnce `
            -RootControl $form `
            -ScaleFactor $scaleFactor
    }

    # Center the fully scaled window on the display where the user launched it.
    $form.StartPosition = [System.Windows.Forms.FormStartPosition]::Manual
    $form.Left = $workingArea.Left + [int](
        ($workingArea.Width - $form.Width) / 2
    )
    $form.Top = $workingArea.Top + [int](
        ($workingArea.Height - $form.Height) / 2
    )

    $versionLabel.Text = "Ver $GuiVersion"
}

function Get-ProgressRatio {
    if ($progressBar.Maximum -le $progressBar.Minimum) {
        return 0.0
    }

    return [math]::Min(
        1.0,
        [math]::Max(
            0.0,
            (
                ($progressBar.Value - $progressBar.Minimum) /
                [double]($progressBar.Maximum - $progressBar.Minimum)
            )
        )
    )
}

function Draw-LightProgress {
    param(
        [Parameter(Mandatory = $true)]
        [System.Drawing.Graphics]$Graphics,

        [Parameter(Mandatory = $true)]
        [System.Drawing.Rectangle]$Bounds
    )

    $backgroundBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(242, 242, 242)
    )
    $fillBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(6, 138, 46)
    )
    $borderPen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(145, 145, 145)
    )

    try {
        $Graphics.FillRectangle($backgroundBrush, $Bounds)
        $inner = [System.Drawing.Rectangle]::new(
            2,
            2,
            [math]::Max(0, $Bounds.Width - 4),
            [math]::Max(0, $Bounds.Height - 4)
        )

        if (
            $progressBar.Style -eq
            [System.Windows.Forms.ProgressBarStyle]::Marquee
        ) {
            $segmentWidth = [math]::Max(45, [int]($inner.Width * 0.24))
            $travel = $inner.Width + $segmentWidth
            $segmentX = (
                ($script:ProgressAnimationOffset * 8) % $travel
            ) - $segmentWidth
            $fillRectangle = [System.Drawing.Rectangle]::new(
                $segmentX,
                $inner.Y,
                $segmentWidth,
                $inner.Height
            )
            $Graphics.FillRectangle($fillBrush, $fillRectangle)
        }
        else {
            $fillWidth = [int]($inner.Width * (Get-ProgressRatio))

            if ($fillWidth -gt 0) {
                $Graphics.FillRectangle(
                    $fillBrush,
                    ([System.Drawing.Rectangle]::new(
                        $inner.X,
                        $inner.Y,
                        $fillWidth,
                        $inner.Height
                    ))
                )
            }
        }

        $borderInset = [int][math]::Max(
            1,
            [math]::Ceiling($borderPen.Width / 2.0)
        )
        $Graphics.DrawRectangle(
            $borderPen,
            $borderInset,
            $borderInset,
            [math]::Max(0, $Bounds.Width - (2 * $borderInset) - 1),
            [math]::Max(0, $Bounds.Height - (2 * $borderInset) - 1)
        )
    }
    finally {
        $backgroundBrush.Dispose()
        $fillBrush.Dispose()
        $borderPen.Dispose()
    }
}

function Draw-DarkProgress {
    param(
        [Parameter(Mandatory = $true)]
        [System.Drawing.Graphics]$Graphics,

        [Parameter(Mandatory = $true)]
        [System.Drawing.Rectangle]$Bounds
    )

    $Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
    $laneWidth = [single][math]::Max(2.0, $Bounds.Height * 0.055)
    $borderWidth = [single][math]::Max(1.0, $Bounds.Height * 0.03)
    $backgroundBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(3, 9, 18)
    )
    $lanePen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(35, 82, 116),
        $laneWidth
    )
    $borderPen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(0, 220, 255),
        $borderWidth
    )
    $pelletBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(70, 225, 255)
    )
    $chomperBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(255, 225, 35)
    )
    $mouthBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(3, 9, 18)
    )
    $milestoneBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(255, 45, 170)
    )
    $textBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(0, 235, 255)
    )
    $percentFont = New-Object System.Drawing.Font(
        "Consolas",
        [single][math]::Max(12.0, $Bounds.Height * 0.38),
        [System.Drawing.FontStyle]::Bold,
        [System.Drawing.GraphicsUnit]::Pixel
    )

    try {
        $Graphics.FillRectangle($backgroundBrush, $Bounds)

        $chomperDiameter = [int][math]::Max(20, $Bounds.Height * 0.68)
        $chomperDiameter = [math]::Min(
            $chomperDiameter,
            [math]::Max(16, $Bounds.Height - 6)
        )
        $chomperRadius = [int]($chomperDiameter / 2)
        $labelWidth = [int][math]::Max(72, $Bounds.Height * 1.8)
        $trackLeft = $chomperRadius + 7
        $trackRight = [math]::Max(
            $trackLeft + $chomperDiameter,
            $Bounds.Width - $labelWidth - $chomperRadius - 7
        )
        $trackWidth = $trackRight - $trackLeft
        $centerY = [int]($Bounds.Height / 2)
        $Graphics.DrawLine(
            $lanePen,
            $trackLeft,
            $centerY,
            $trackRight,
            $centerY
        )

        $ratio = Get-ProgressRatio

        if (
            $progressBar.Style -eq
            [System.Windows.Forms.ProgressBarStyle]::Marquee
        ) {
            $ratio = (
                ($script:ProgressAnimationOffset * 3) % 100
            ) / 100.0
        }

        $chomperX = $trackLeft + [int]($trackWidth * $ratio)
        $pelletDiameter = [int][math]::Max(4, $Bounds.Height * 0.14)
        $pelletRadius = [int]($pelletDiameter / 2)
        $pelletSpacing = [int][math]::Max(15, $Bounds.Height * 0.48)

        for (
            $pelletX = $trackLeft + $pelletSpacing;
            $pelletX -lt $trackRight;
            $pelletX += $pelletSpacing
        ) {
            if ($pelletX -gt ($chomperX + $chomperRadius)) {
                $Graphics.FillEllipse(
                    $pelletBrush,
                    $pelletX - $pelletRadius,
                    $centerY - $pelletRadius,
                    $pelletDiameter,
                    $pelletDiameter
                )
            }
        }

        $markerRadius = [int][math]::Max(3, $Bounds.Height * 0.085)
        $markerY = $markerRadius + 2

        foreach ($milestone in @(0.25, 0.5, 0.75)) {
            $diamondX = $trackLeft + [int]($trackWidth * $milestone)
            $diamond = [System.Drawing.Point[]]@(
                [System.Drawing.Point]::new(
                    [int]$diamondX,
                    [int]($markerY - $markerRadius)
                ),
                [System.Drawing.Point]::new(
                    [int]($diamondX + $markerRadius),
                    [int]$markerY
                ),
                [System.Drawing.Point]::new(
                    [int]$diamondX,
                    [int]($markerY + $markerRadius)
                ),
                [System.Drawing.Point]::new(
                    [int]($diamondX - $markerRadius),
                    [int]$markerY
                )
            )
            $Graphics.FillPolygon($milestoneBrush, $diamond)
        }

        $chomperY = $centerY - $chomperRadius
        $Graphics.FillEllipse(
            $chomperBrush,
            $chomperX - $chomperRadius,
            $chomperY,
            $chomperDiameter,
            $chomperDiameter
        )
        $mouthReach = [int][math]::Max(7, $chomperDiameter * 0.55)
        $mouthHalfHeight = [int][math]::Max(5, $chomperDiameter * 0.28)
        $mouth = [System.Drawing.Point[]]@(
            [System.Drawing.Point]::new([int]$chomperX, [int]$centerY),
            [System.Drawing.Point]::new(
                [int]($chomperX + $mouthReach),
                [int]($centerY - $mouthHalfHeight)
            ),
            [System.Drawing.Point]::new(
                [int]($chomperX + $mouthReach),
                [int]($centerY + $mouthHalfHeight)
            )
        )
        $Graphics.FillPolygon($mouthBrush, $mouth)

        $percentText = if (
            $progressBar.Style -eq
            [System.Windows.Forms.ProgressBarStyle]::Marquee
        ) {
            "RUN"
        }
        else {
            "{0}%" -f [int][math]::Round($ratio * 100)
        }

        $textRectangle = [System.Drawing.RectangleF]::new(
            $Bounds.Width - $labelWidth,
            0,
            $labelWidth - 4,
            $Bounds.Height
        )
        $format = New-Object System.Drawing.StringFormat
        $format.Alignment = [System.Drawing.StringAlignment]::Center
        $format.LineAlignment = [System.Drawing.StringAlignment]::Center

        try {
            $Graphics.DrawString(
                $percentText,
                $percentFont,
                $textBrush,
                $textRectangle,
                $format
            )
        }
        finally {
            $format.Dispose()
        }

        $borderInset = [int][math]::Max(
            1,
            [math]::Ceiling($borderPen.Width / 2.0)
        )
        $Graphics.DrawRectangle(
            $borderPen,
            $borderInset,
            $borderInset,
            [math]::Max(0, $Bounds.Width - (2 * $borderInset) - 1),
            [math]::Max(0, $Bounds.Height - (2 * $borderInset) - 1)
        )
    }
    finally {
        $backgroundBrush.Dispose()
        $lanePen.Dispose()
        $borderPen.Dispose()
        $pelletBrush.Dispose()
        $chomperBrush.Dispose()
        $mouthBrush.Dispose()
        $milestoneBrush.Dispose()
        $textBrush.Dispose()
        $percentFont.Dispose()
    }
}

function Draw-FightProgress {
    param(
        [Parameter(Mandatory = $true)]
        [System.Drawing.Graphics]$Graphics,

        [Parameter(Mandatory = $true)]
        [System.Drawing.Rectangle]$Bounds
    )

    $Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
    $borderWidth = [single][math]::Max(2.0, $Bounds.Height * 0.045)
    $railWidth = [single][math]::Max(1.0, $Bounds.Height * 0.025)
    $backgroundBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(5, 13, 26)
    )
    $emptyBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(19, 31, 48)
    )
    $blueBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(0, 145, 255)
    )
    $redBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(230, 48, 35)
    )
    $goldBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(255, 190, 35)
    )
    $medallionBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::FromArgb(20, 29, 44)
    )
    $borderPen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(255, 184, 35),
        $borderWidth
    )
    $bluePen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(80, 205, 255),
        $railWidth
    )
    $redPen = New-Object System.Drawing.Pen(
        [System.Drawing.Color]::FromArgb(255, 106, 45),
        $railWidth
    )
    $textBrush = New-Object System.Drawing.SolidBrush(
        [System.Drawing.Color]::White
    )
    $percentFont = New-Object System.Drawing.Font(
        "Segoe UI",
        [single][math]::Max(12.0, $Bounds.Height * 0.36),
        [System.Drawing.FontStyle]::Bold,
        [System.Drawing.GraphicsUnit]::Pixel
    )

    try {
        $Graphics.FillRectangle($backgroundBrush, $Bounds)
        $centerX = [int]($Bounds.Width / 2)
        $medallionWidth = [int][math]::Max(58, $Bounds.Height * 1.45)
        $halfGap = [int]($medallionWidth / 2) + 5
        $barHeight = [int][math]::Max(12, $Bounds.Height * 0.42)
        $barY = [int](($Bounds.Height - $barHeight) / 2)
        $sidePadding = [int][math]::Max(8, $Bounds.Height * 0.22)
        $leftX = $sidePadding
        $leftWidth = [math]::Max(1, $centerX - $halfGap - $leftX)
        $rightX = $centerX + $halfGap
        $rightWidth = [math]::Max(
            1,
            $Bounds.Width - $rightX - $sidePadding
        )

        $Graphics.FillRectangle(
            $emptyBrush,
            $leftX,
            $barY,
            $leftWidth,
            $barHeight
        )
        $Graphics.FillRectangle(
            $emptyBrush,
            $rightX,
            $barY,
            $rightWidth,
            $barHeight
        )

        $ratio = Get-ProgressRatio

        if (
            $progressBar.Style -eq
            [System.Windows.Forms.ProgressBarStyle]::Marquee
        ) {
            $pulse = (
                ($script:ProgressAnimationOffset * 4) % 100
            ) / 100.0
            $ratio = if ($pulse -le 0.5) {
                $pulse * 2
            }
            else {
                (1.0 - $pulse) * 2
            }
        }

        $leftFillWidth = [int]($leftWidth * $ratio)
        $rightFillWidth = [int]($rightWidth * (1.0 - $ratio))

        if ($leftFillWidth -gt 0) {
            $Graphics.FillRectangle(
                $blueBrush,
                $leftX,
                $barY,
                $leftFillWidth,
                $barHeight
            )
        }

        if ($rightFillWidth -gt 0) {
            $Graphics.FillRectangle(
                $redBrush,
                $rightX + $rightWidth - $rightFillWidth,
                $barY,
                $rightFillWidth,
                $barHeight
            )
        }

        $Graphics.DrawRectangle(
            $bluePen,
            $leftX,
            $barY,
            $leftWidth,
            $barHeight
        )
        $Graphics.DrawRectangle(
            $redPen,
            $rightX,
            $barY,
            $rightWidth,
            $barHeight
        )

        $markerDiameter = [int][math]::Max(4, $Bounds.Height * 0.12)
        $markerRadius = [int]($markerDiameter / 2)

        foreach ($milestone in @(0.25, 0.5, 0.75)) {
            $markerX = if ($milestone -le 0.5) {
                $leftX + [int]($leftWidth * ($milestone * 2))
            }
            else {
                $rightX + [int]($rightWidth * (($milestone - 0.5) * 2))
            }
            $Graphics.FillEllipse(
                $goldBrush,
                $markerX - $markerRadius,
                3,
                $markerDiameter,
                $markerDiameter
            )
        }

        $medallionRectangle = [System.Drawing.Rectangle]::new(
            $centerX - [int]($medallionWidth / 2),
            2,
            $medallionWidth,
            [math]::Max(12, $Bounds.Height - 5)
        )
        $Graphics.FillEllipse($medallionBrush, $medallionRectangle)
        $Graphics.DrawEllipse($borderPen, $medallionRectangle)

        $percentText = if (
            $progressBar.Style -eq
            [System.Windows.Forms.ProgressBarStyle]::Marquee
        ) {
            "VS"
        }
        else {
            "{0}%" -f [int][math]::Round($ratio * 100)
        }

        $format = New-Object System.Drawing.StringFormat
        $format.Alignment = [System.Drawing.StringAlignment]::Center
        $format.LineAlignment = [System.Drawing.StringAlignment]::Center

        try {
            $Graphics.DrawString(
                $percentText,
                $percentFont,
                $textBrush,
                [System.Drawing.RectangleF]$medallionRectangle,
                $format
            )
        }
        finally {
            $format.Dispose()
        }

        $borderInset = [int][math]::Max(
            1,
            [math]::Ceiling($borderPen.Width / 2.0)
        )
        $Graphics.DrawRectangle(
            $borderPen,
            $borderInset,
            $borderInset,
            [math]::Max(0, $Bounds.Width - (2 * $borderInset) - 1),
            [math]::Max(0, $Bounds.Height - (2 * $borderInset) - 1)
        )
    }
    finally {
        $backgroundBrush.Dispose()
        $emptyBrush.Dispose()
        $blueBrush.Dispose()
        $redBrush.Dispose()
        $goldBrush.Dispose()
        $medallionBrush.Dispose()
        $borderPen.Dispose()
        $bluePen.Dispose()
        $redPen.Dispose()
        $textBrush.Dispose()
        $percentFont.Dispose()
    }
}

function Draw-ThemeProgress {
    param(
        [Parameter(Mandatory = $true)]
        [System.Drawing.Graphics]$Graphics,

        [Parameter(Mandatory = $true)]
        [System.Drawing.Rectangle]$Bounds
    )

    switch ($script:CurrentTheme) {
        "Dark" {
            Draw-DarkProgress -Graphics $Graphics -Bounds $Bounds
        }
        "Fight" {
            Draw-FightProgress -Graphics $Graphics -Bounds $Bounds
        }
        default {
            Draw-LightProgress -Graphics $Graphics -Bounds $Bounds
        }
    }
}

function Draw-HeaderArtwork {
    param(
        [Parameter(Mandatory = $true)]
        [System.Drawing.Graphics]$Graphics,

        [Parameter(Mandatory = $true)]
        [System.Drawing.Rectangle]$Bounds
    )

    $Graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias

    if ($script:CurrentTheme -eq "Fight") {
        if ($null -ne $script:FightMascotImage) {
            $clipState = $Graphics.Save()
            $portraitPath = New-Object System.Drawing.Drawing2D.GraphicsPath

            try {
                $portraitPath.AddEllipse(
                    1,
                    1,
                    [math]::Max(1, $Bounds.Width - 2),
                    [math]::Max(1, $Bounds.Height - 2)
                )
                $Graphics.SetClip($portraitPath)
                $Graphics.DrawImage(
                    $script:FightMascotImage,
                    ([System.Drawing.Rectangle]::new(
                        1,
                        1,
                        [math]::Max(1, $Bounds.Width - 2),
                        [math]::Max(1, $Bounds.Height - 2)
                    ))
                )
            }
            finally {
                $portraitPath.Dispose()
                $Graphics.Restore($clipState)
            }
        }

        return
    }

    if ($script:CurrentTheme -eq "Dark") {
        $Graphics.Clear([System.Drawing.Color]::FromArgb(5, 11, 22))
        $artworkState = $Graphics.Save()
        $Graphics.ScaleTransform(
            [single]($Bounds.Width / 62.0),
            [single]($Bounds.Height / 62.0)
        )
        $cabinetBrush = New-Object System.Drawing.SolidBrush(
            [System.Drawing.Color]::FromArgb(16, 28, 48)
        )
        $screenBrush = New-Object System.Drawing.SolidBrush(
            [System.Drawing.Color]::FromArgb(255, 45, 170)
        )
        $controlBrush = New-Object System.Drawing.SolidBrush(
            [System.Drawing.Color]::FromArgb(0, 225, 255)
        )
        $outlinePen = New-Object System.Drawing.Pen(
            [System.Drawing.Color]::FromArgb(0, 225, 255),
            2
        )

        try {
            $cabinet = [System.Drawing.Point[]]@(
                (New-Object System.Drawing.Point(16, 5)),
                (New-Object System.Drawing.Point(47, 5)),
                (New-Object System.Drawing.Point(51, 31)),
                (New-Object System.Drawing.Point(45, 38)),
                (New-Object System.Drawing.Point(48, 57)),
                (New-Object System.Drawing.Point(14, 57)),
                (New-Object System.Drawing.Point(17, 38)),
                (New-Object System.Drawing.Point(11, 31))
            )
            $Graphics.FillPolygon($cabinetBrush, $cabinet)
            $Graphics.DrawPolygon($outlinePen, $cabinet)
            $Graphics.FillRectangle($screenBrush, 19, 12, 25, 17)
            $Graphics.FillEllipse($controlBrush, 23, 35, 6, 6)
            $Graphics.FillEllipse($screenBrush, 35, 35, 5, 5)
            $Graphics.DrawLine($outlinePen, 23, 49, 40, 49)
        }
        finally {
            $cabinetBrush.Dispose()
            $screenBrush.Dispose()
            $controlBrush.Dispose()
            $outlinePen.Dispose()
            $Graphics.Restore($artworkState)
        }
    }
}

function Get-ThemeScaleFactor {
    return [math]::Max(1.0, [double]$script:DisplayScaleFactor)
}

function New-ThemePoint {
    param(
        [Parameter(Mandatory = $true)]
        [int]$X,

        [Parameter(Mandatory = $true)]
        [int]$Y
    )

    $scaleFactor = Get-ThemeScaleFactor
    return [System.Drawing.Point]::new(
        [int][math]::Round($X * $scaleFactor),
        [int][math]::Round($Y * $scaleFactor)
    )
}

function New-ThemePixelFont {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Family,

        [Parameter(Mandatory = $true)]
        [double]$Size,

        [System.Drawing.FontStyle]$Style = (
            [System.Drawing.FontStyle]::Regular
        )
    )

    return [System.Drawing.Font]::new(
        $Family,
        [single]($Size * (Get-ThemeScaleFactor)),
        $Style,
        [System.Drawing.GraphicsUnit]::Pixel
    )
}

function Set-FixedThemeButtonAppearance {
    foreach ($button in @($themeToggleButton)) {
        $button.UseVisualStyleBackColor = $false
        $button.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
        $button.BackColor = [System.Drawing.Color]::Black
        $button.ForeColor = [System.Drawing.Color]::White
        $button.FlatAppearance.BorderColor = [System.Drawing.Color]::DimGray
        $button.FlatAppearance.BorderSize = 1
        $button.FlatAppearance.MouseOverBackColor = (
            [System.Drawing.Color]::FromArgb(32, 32, 32)
        )
        $button.FlatAppearance.MouseDownBackColor = (
            [System.Drawing.Color]::FromArgb(55, 55, 55)
        )
        $button.Font = New-ThemePixelFont `
            -Family "Segoe UI" `
            -Size 12 `
            -Style ([System.Drawing.FontStyle]::Bold)
        $button.BringToFront()
    }
}

function Set-ThemeTabAppearance {
    $selectedIndex = $tabControl.SelectedIndex
    $tabButtons = @($imageTabButton, $videoTabButton, $settingsTabButton)

    switch ($script:CurrentTheme) {
        "Dark" {
            $tabHeaderPanel.BackColor = [System.Drawing.Color]::FromArgb(5, 11, 22)

            for ($index = 0; $index -lt $tabButtons.Count; $index++) {
                $button = $tabButtons[$index]
                $button.BackColor = if ($index -eq $selectedIndex) {
                    [System.Drawing.Color]::FromArgb(9, 43, 61)
                }
                else {
                    [System.Drawing.Color]::FromArgb(9, 19, 34)
                }
                $button.ForeColor = if ($index -eq 0) {
                    [System.Drawing.Color]::FromArgb(0, 232, 255)
                }
                else {
                    [System.Drawing.Color]::FromArgb(255, 73, 178)
                }
                $button.FlatAppearance.BorderColor = $button.ForeColor
            }
        }
        "Fight" {
            $tabHeaderPanel.BackColor = [System.Drawing.Color]::FromArgb(7, 16, 31)

            for ($index = 0; $index -lt $tabButtons.Count; $index++) {
                $button = $tabButtons[$index]

                if ($index -eq $selectedIndex) {
                    $button.BackColor = if ($index -eq 0) {
                        [System.Drawing.Color]::FromArgb(150, 36, 27)
                    }
                    else {
                        [System.Drawing.Color]::FromArgb(5, 74, 125)
                    }
                }
                else {
                    $button.BackColor = [System.Drawing.Color]::FromArgb(9, 25, 45)
                }

                $button.ForeColor = [System.Drawing.Color]::FromArgb(255, 235, 190)
                $button.FlatAppearance.BorderColor = if ($index -eq 0) {
                    [System.Drawing.Color]::FromArgb(245, 70, 40)
                }
                else {
                    [System.Drawing.Color]::FromArgb(30, 155, 255)
                }
            }
        }
        default {
            $tabHeaderPanel.BackColor = [System.Drawing.SystemColors]::Control

            for ($index = 0; $index -lt $tabButtons.Count; $index++) {
                $button = $tabButtons[$index]
                $button.BackColor = if ($index -eq $selectedIndex) {
                    [System.Drawing.SystemColors]::Window
                }
                else {
                    [System.Drawing.SystemColors]::Control
                }
                $button.ForeColor = [System.Drawing.SystemColors]::ControlText
                $button.FlatAppearance.BorderColor = (
                    [System.Drawing.SystemColors]::ControlDark
                )
            }
        }
    }

    foreach ($button in $tabButtons) {
        $button.UseVisualStyleBackColor = $false
        $button.FlatStyle = [System.Windows.Forms.FlatStyle]::Flat
        $button.FlatAppearance.BorderSize = 1
        $button.Font = New-ThemePixelFont `
            -Family "Segoe UI" `
            -Size 12 `
            -Style ([System.Drawing.FontStyle]::Bold)
    }

    $tabHeaderPanel.Invalidate()
}

function Update-VideoOptionNotes {
    switch ($script:CurrentTheme) {
        "Dark" {
            $normalNoteColor = [System.Drawing.Color]::FromArgb(175, 190, 205)
            $warningNoteColor = [System.Drawing.Color]::FromArgb(255, 95, 185)
        }
        "Fight" {
            $normalNoteColor = [System.Drawing.Color]::FromArgb(235, 225, 198)
            $warningNoteColor = [System.Drawing.Color]::FromArgb(255, 190, 35)
        }
        default {
            $normalNoteColor = [System.Drawing.Color]::DimGray
            $warningNoteColor = [System.Drawing.Color]::DarkGoldenrod
        }
    }

    $selectedProfileChoice = Get-SelectedVideoProfileChoice
    if ($selectedProfileChoice -eq 7) {
        $videoProfileInfoLabel.Text = "Only recommended for very light emulation devices. Use test files to verify playback before converting a full library."
        $videoProfileInfoLabel.ForeColor = $warningNoteColor
    }
    elseif ($selectedProfileChoice -eq 3) {
        $videoProfileInfoLabel.Text = "Recommended for desktop PCs, Switch, Steam Deck, or similar devices."
        $videoProfileInfoLabel.ForeColor = $normalNoteColor
    }
    else {
        $videoProfileInfoLabel.Text = ""
        $videoProfileInfoLabel.ForeColor = $normalNoteColor
    }

    if ($encoderModeCombo.SelectedIndex -eq 1) {
        $encoderModeInfoLabel.Text = "Best when maximum space savings matter on lightweight devices. It takes much longer and usually saves only a little more space."
        $encoderModeInfoLabel.ForeColor = $warningNoteColor
    }
    else {
        $encoderModeInfoLabel.Text = ""
        $encoderModeInfoLabel.ForeColor = $normalNoteColor
    }

    $videoTestInfoLabel.ForeColor = $normalNoteColor
}

