$progressDisplay.Add_Paint({
    Draw-ThemeProgress `
        -Graphics $_.Graphics `
        -Bounds $progressDisplay.ClientRectangle
})

$headerArtworkPanel.Add_Paint({
    Draw-HeaderArtwork `
        -Graphics $_.Graphics `
        -Bounds $headerArtworkPanel.ClientRectangle
})

$form.Add_Paint({
    $themeScale = Get-ThemeScaleFactor
    $headerHeight = [int][math]::Round(78 * $themeScale)

    if ($script:CurrentTheme -eq "Dark") {
        $gridSpacing = [int][math]::Max(18, [math]::Round(18 * $themeScale))
        $gridPen = New-Object System.Drawing.Pen(
            [System.Drawing.Color]::FromArgb(24, 0, 210, 245),
            [single][math]::Max(1.0, $themeScale)
        )

        try {
            for (
                $x = 0;
                $x -lt $form.ClientSize.Width;
                $x += $gridSpacing
            ) {
                $_.Graphics.DrawLine($gridPen, $x, 0, $x, $headerHeight)
            }

            for ($y = 0; $y -lt $headerHeight; $y += $gridSpacing) {
                $_.Graphics.DrawLine(
                    $gridPen,
                    0,
                    $y,
                    $form.ClientSize.Width,
                    $y
                )
            }
        }
        finally {
            $gridPen.Dispose()
        }
    }
    elseif ($script:CurrentTheme -eq "Fight") {
        $bluePen = New-Object System.Drawing.Pen(
            [System.Drawing.Color]::FromArgb(95, 0, 130, 235),
            [single](3 * $themeScale)
        )
        $redPen = New-Object System.Drawing.Pen(
            [System.Drawing.Color]::FromArgb(105, 225, 48, 35),
            [single](3 * $themeScale)
        )
        $goldPen = New-Object System.Drawing.Pen(
            [System.Drawing.Color]::FromArgb(65, 255, 190, 35),
            [single][math]::Max(1.0, $themeScale)
        )

        try {
            $_.Graphics.DrawLine(
                $bluePen,
                0,
                [int](72 * $themeScale),
                [int](285 * $themeScale),
                [int](2 * $themeScale)
            )
            $_.Graphics.DrawLine(
                $redPen,
                $form.ClientSize.Width - [int](300 * $themeScale),
                [int](2 * $themeScale),
                $form.ClientSize.Width,
                [int](73 * $themeScale)
            )
            $_.Graphics.DrawLine(
                $goldPen,
                0,
                [int](77 * $themeScale),
                $form.ClientSize.Width,
                [int](77 * $themeScale)
            )
        }
        finally {
            $bluePen.Dispose()
            $redPen.Dispose()
            $goldPen.Dispose()
        }
    }
})

