function Test-AllRequiredTools {
    return (
        (Test-RequiredToolUsable -Name "cwebp.exe" -Arguments @("-version")) -and
        (Test-RequiredToolUsable -Name "ffmpeg.exe" -Arguments @("-version")) -and
        (Test-RequiredToolUsable -Name "ffprobe.exe" -Arguments @("-version"))
    )
}

function Test-RequiredToolUsable {
    param(
        [Parameter(Mandatory = $true)][string]$Name,
        [Parameter(Mandatory = $true)][string[]]$Arguments
    )
    $path = Get-RequiredToolPath -Name $Name
    if (-not (Test-Path -LiteralPath $path -PathType Leaf)) { return $false }
    try {
        $info = New-Object Diagnostics.ProcessStartInfo
        $info.FileName = $path
        $info.Arguments = $Arguments -join " "
        $info.UseShellExecute = $false
        $info.CreateNoWindow = $true
        $info.RedirectStandardOutput = $true
        $info.RedirectStandardError = $true
        $process = [Diagnostics.Process]::Start($info)
        if (-not $process.WaitForExit(5000)) {
            $process.Kill()
            $process.Dispose()
            return $false
        }
        $usable = ($process.ExitCode -eq 0)
        $process.Dispose()
        return $usable
    }
    catch { return $false }
}

function Update-ToolStatus {
    $cwebpFound = Test-RequiredToolUsable -Name "cwebp.exe" -Arguments @("-version")
    $ffmpegFound = Test-RequiredToolUsable -Name "ffmpeg.exe" -Arguments @("-version")
    $ffprobeFound = Test-RequiredToolUsable -Name "ffprobe.exe" -Arguments @("-version")
    $allFound = ($cwebpFound -and $ffmpegFound -and $ffprobeFound)

    $check = [char]0x2713
    $cross = [char]0x2718
    $cwebpStatusLabel.Text = "$(if ($cwebpFound) {$check} else {$cross})  cwebp.exe  $(if ($cwebpFound) {'Available'} else {'Missing or unusable'})"
    $ffmpegStatusLabel.Text = "$(if ($ffmpegFound) {$check} else {$cross})  ffmpeg.exe  $(if ($ffmpegFound) {'Available'} else {'Missing or unusable'})"
    $ffprobeStatusLabel.Text = "$(if ($ffprobeFound) {$check} else {$cross})  ffprobe.exe  $(if ($ffprobeFound) {'Available'} else {'Missing or unusable'})"

    foreach ($pair in @(
        @($cwebpStatusLabel, $cwebpFound),
        @($ffmpegStatusLabel, $ffmpegFound),
        @($ffprobeStatusLabel, $ffprobeFound)
    )) {
        $pair[0].ForeColor = if ($pair[1]) {
            [Drawing.Color]::FromArgb(40, 180, 80)
        } else {
            [Drawing.Color]::FromArgb(220, 55, 55)
        }
    }

    if ($allFound) {
        $downloadToolsButton.Text = "Update Tools"
    }
    else {
        $downloadToolsButton.Text = "Download Tools"
    }

    return $allFound
}

function Get-ToolDownloaderSource {
    $destinationLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $ApplicationRoot
    $guiVersionLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $GuiVersion

    $source = @'
#requires -version 5.1
$ErrorActionPreference = "Stop"

$DestinationFolder = __DESTINATION_LITERAL__
$GuiVersion = __GUI_VERSION_LITERAL__

$WebPArchiveUrl = "https://storage.googleapis.com/downloads.webmproject.org/releases/webp/libwebp-1.6.0-windows-x64.zip"
$FFmpegArchiveUrl = "https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip"
$FFmpegChecksumUrl = "https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip.sha256"

[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
Add-Type -AssemblyName System.Net.Http
Add-Type -AssemblyName System.IO.Compression.FileSystem

function Write-ToolStep {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Output "[TOOLS] $Message"
}

function Download-FileWithProgress {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Url,

        [Parameter(Mandatory = $true)]
        [string]$Destination,

        [Parameter(Mandatory = $true)]
        [string]$Label
    )

    $handler = New-Object System.Net.Http.HttpClientHandler
    $client = New-Object System.Net.Http.HttpClient($handler)
    $client.Timeout = [TimeSpan]::FromMinutes(30)
    $client.DefaultRequestHeaders.UserAgent.ParseAdd(
        "SYYBOTTS-Media-Optimizer-GUI/$GuiVersion"
    )

    try {
        $response = $client.GetAsync(
            $Url,
            [System.Net.Http.HttpCompletionOption]::ResponseHeadersRead
        ).Result

        $response.EnsureSuccessStatusCode()
        $totalLength = $response.Content.Headers.ContentLength
        $inputStream = $response.Content.ReadAsStreamAsync().Result
        $outputStream = New-Object System.IO.FileStream(
            $Destination,
            [System.IO.FileMode]::Create,
            [System.IO.FileAccess]::Write,
            [System.IO.FileShare]::None
        )

        try {
            $buffer = New-Object byte[] (1MB)
            [long]$downloaded = 0
            $lastPercent = -1
            $lastOutput = [DateTime]::MinValue

            while (($read = $inputStream.Read($buffer, 0, $buffer.Length)) -gt 0) {
                $outputStream.Write($buffer, 0, $read)
                $downloaded += $read

                if ($totalLength -and $totalLength -gt 0) {
                    $percent = [math]::Min(
                        100,
                        [int](($downloaded * 100L) / $totalLength)
                    )

                    if (
                        $percent -ne $lastPercent -and
                        (
                            $percent -eq 100 -or
                            ([DateTime]::UtcNow - $lastOutput).TotalMilliseconds -ge 400
                        )
                    ) {
                        Write-Output ("[DOWNLOAD] {0} {1}%" -f $Label, $percent)
                        $lastPercent = $percent
                        $lastOutput = [DateTime]::UtcNow
                    }
                }
            }

            $outputStream.Flush()
        }
        finally {
            $outputStream.Dispose()
            $inputStream.Dispose()
            $response.Dispose()
        }

        Write-Output ("[DOWNLOAD] {0} 100%" -f $Label)
    }
    finally {
        $client.Dispose()
        $handler.Dispose()
    }
}

function Format-TransferSize {
    param(
        [Parameter(Mandatory = $true)]
        [double]$Bytes
    )

    if ($Bytes -ge 1GB) {
        return ("{0:N2} GB" -f ($Bytes / 1GB))
    }

    return ("{0:N1} MB" -f ($Bytes / 1MB))
}

function Format-TransferEta {
    param(
        [Parameter(Mandatory = $true)]
        [double]$Seconds
    )

    if (
        [double]::IsNaN($Seconds) -or
        [double]::IsInfinity($Seconds) -or
        $Seconds -lt 0
    ) {
        return "calculating"
    }

    $timeSpan = [TimeSpan]::FromSeconds(
        [math]::Min($Seconds, 359999)
    )

    if ($timeSpan.TotalHours -ge 1) {
        return $timeSpan.ToString("hh\:mm\:ss")
    }

    return $timeSpan.ToString("mm\:ss")
}

function Start-BitsDownloadsWithProgress {
    param(
        [Parameter(Mandatory = $true)]
        [object[]]$Downloads
    )

    Import-Module BitsTransfer -ErrorAction Stop

    # Clear abandoned jobs from an earlier interrupted tool-download run.
    Get-BitsTransfer -ErrorAction SilentlyContinue |
        Where-Object {
            $_.DisplayName -like "SYYBOTTS Media Optimizer Tools *"
        } |
        Remove-BitsTransfer -ErrorAction SilentlyContinue

    $sessionId = [guid]::NewGuid().ToString("N")
    $trackedJobs = New-Object System.Collections.Generic.List[object]
    $completedSuccessfully = $false

    try {
        foreach ($download in $Downloads) {
            Remove-Item `
                -LiteralPath $download.Destination `
                -Force `
                -ErrorAction SilentlyContinue

            $job = Start-BitsTransfer `
                -Source $download.Url `
                -Destination $download.Destination `
                -DisplayName (
                    "SYYBOTTS Media Optimizer Tools {0} - {1}" -f
                    $sessionId,
                    $download.Label
                ) `
                -Description "Required optimizer tool download" `
                -Priority Foreground `
                -Asynchronous `
                -ErrorAction Stop

            $trackedJobs.Add(
                [pscustomobject]@{
                    JobId = $job.JobId
                    Label = $download.Label
                    Destination = $download.Destination
                    Completed = $false
                    LastTransferred = 0L
                }
            )
        }

        $lastSampleTime = [DateTime]::UtcNow
        [double]$lastCombinedTransferred = 0
        $lastReportedPercent = -1
        $lastReportTime = [DateTime]::MinValue

        while ($true) {
            [double]$combinedTransferred = 0
            [double]$combinedTotal = 0
            $allTotalsKnown = $true
            $allCompleted = $true
            $statusParts = New-Object System.Collections.Generic.List[string]

            foreach ($tracked in $trackedJobs) {
                if ($tracked.Completed) {
                    $fileLength = 0L

                    if (Test-Path -LiteralPath $tracked.Destination -PathType Leaf) {
                        $fileLength = (
                            Get-Item -LiteralPath $tracked.Destination
                        ).Length
                    }

                    $combinedTransferred += $fileLength
                    $combinedTotal += $fileLength
                    $statusParts.Add("$($tracked.Label) 100%")
                    continue
                }

                $allCompleted = $false
                $job = Get-BitsTransfer `
                    -JobId $tracked.JobId `
                    -ErrorAction SilentlyContinue

                if ($null -eq $job) {
                    throw "The BITS job for $($tracked.Label) disappeared before completion."
                }

                $state = [string]$job.JobState

                if ($state -eq "Error") {
                    $errorText = $job.ErrorDescription

                    if ([string]::IsNullOrWhiteSpace($errorText)) {
                        $errorText = "Unknown BITS transfer error."
                    }

                    throw "$($tracked.Label) download failed: $errorText"
                }

                if ($state -eq "Cancelled") {
                    throw "$($tracked.Label) download was cancelled."
                }

                [double]$bytesTransferred = $job.BytesTransferred
                [double]$bytesTotal = $job.BytesTotal

                $totalKnown = (
                    $bytesTotal -gt 0 -and
                    $bytesTotal -lt [double][long]::MaxValue
                )

                if (-not $totalKnown) {
                    $allTotalsKnown = $false
                    $combinedTransferred += $bytesTransferred
                    $statusParts.Add(
                        ("{0} {1}" -f
                        $tracked.Label,
                        (Format-TransferSize -Bytes $bytesTransferred))
                    )
                }
                else {
                    $combinedTransferred += $bytesTransferred
                    $combinedTotal += $bytesTotal

                    $filePercent = [math]::Min(
                        100,
                        [int](($bytesTransferred * 100.0) / $bytesTotal)
                    )

                    $statusParts.Add(
                        ("{0} {1}%" -f $tracked.Label, $filePercent)
                    )
                }

                if ($state -eq "Transferred") {
                    Complete-BitsTransfer -BitsJob $job -ErrorAction Stop
                    $tracked.Completed = $true

                    $installedLength = (
                        Get-Item -LiteralPath $tracked.Destination
                    ).Length

                    # Replace the pre-completion count with the final file size.
                    $combinedTransferred -= $bytesTransferred
                    $combinedTransferred += $installedLength

                    if ($totalKnown) {
                        $combinedTotal -= $bytesTotal
                        $combinedTotal += $installedLength
                    }

                    $statusParts[$statusParts.Count - 1] = (
                        "$($tracked.Label) 100%"
                    )
                }
            }

            $now = [DateTime]::UtcNow
            $sampleSeconds = ($now - $lastSampleTime).TotalSeconds
            [double]$bytesPerSecond = 0

            if ($sampleSeconds -gt 0) {
                $bytesPerSecond = [math]::Max(
                    0,
                    ($combinedTransferred - $lastCombinedTransferred) /
                    $sampleSeconds
                )
            }

            $lastSampleTime = $now
            $lastCombinedTransferred = $combinedTransferred

            $overallPercent = 0
            $etaText = "calculating"

            if ($allTotalsKnown -and $combinedTotal -gt 0) {
                $overallPercent = [math]::Min(
                    100,
                    [int](($combinedTransferred * 100.0) / $combinedTotal)
                )

                if ($bytesPerSecond -gt 0) {
                    $etaText = Format-TransferEta -Seconds (
                        ($combinedTotal - $combinedTransferred) /
                        $bytesPerSecond
                    )
                }
            }

            $speedText = if ($bytesPerSecond -gt 0) {
                "{0:N2} MB/s" -f ($bytesPerSecond / 1MB)
            }
            else {
                "calculating"
            }

            $sizeText = if ($allTotalsKnown -and $combinedTotal -gt 0) {
                "{0} / {1}" -f
                (Format-TransferSize -Bytes $combinedTransferred),
                (Format-TransferSize -Bytes $combinedTotal)
            }
            else {
                Format-TransferSize -Bytes $combinedTransferred
            }

            if (
                $overallPercent -ne $lastReportedPercent -or
                ($now - $lastReportTime).TotalSeconds -ge 1 -or
                $allCompleted
            ) {
                Write-Output (
                    "[DOWNLOAD] {0}% | {1} | {2} | ETA {3} | {4}" -f
                    $overallPercent,
                    $sizeText,
                    $speedText,
                    $etaText,
                    ($statusParts -join ", ")
                )

                $lastReportedPercent = $overallPercent
                $lastReportTime = $now
            }

            if ($allCompleted) {
                break
            }

            Start-Sleep -Milliseconds 500
        }

        foreach ($download in $Downloads) {
            if (
                -not (Test-Path -LiteralPath $download.Destination -PathType Leaf) -or
                (Get-Item -LiteralPath $download.Destination).Length -lt 1
            ) {
                throw "BITS did not create a valid file for $($download.Label)."
            }
        }

        $completedSuccessfully = $true
    }
    finally {
        if (-not $completedSuccessfully) {
            foreach ($tracked in $trackedJobs) {
                if (-not $tracked.Completed) {
                    $job = Get-BitsTransfer `
                        -JobId $tracked.JobId `
                        -ErrorAction SilentlyContinue

                    if ($null -ne $job) {
                        Remove-BitsTransfer `
                            -BitsJob $job `
                            -ErrorAction SilentlyContinue
                    }
                }
            }
        }
    }
}

function Download-RequiredArchives {
    param(
        [Parameter(Mandatory = $true)]
        [object[]]$Downloads
    )

    try {
        Write-Output "[STAGE] Starting foreground BITS downloads..."
        Start-BitsDownloadsWithProgress -Downloads $Downloads
        Write-ToolStep "BITS downloads completed."
    }
    catch {
        Write-ToolStep (
            "BITS could not complete the downloads: {0}" -f
            $_.Exception.Message
        )
        Write-ToolStep "Falling back to the standard HTTP downloader."

        foreach ($download in $Downloads) {
            Write-Output (
                "[STAGE] Downloading {0} with the HTTP fallback..." -f
                $download.Label
            )

            Download-FileWithProgress `
                -Url $download.Url `
                -Destination $download.Destination `
                -Label $download.Label
        }
    }
}

function Install-FileAtomic {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Source,

        [Parameter(Mandatory = $true)]
        [string]$Destination
    )

    $newPath = "$Destination.download-new"
    $backupPath = "$Destination.download-backup"

    Remove-Item -LiteralPath $newPath -Force -ErrorAction SilentlyContinue

    if (Test-Path -LiteralPath $backupPath -PathType Leaf) {
        if (-not (Test-Path -LiteralPath $Destination -PathType Leaf)) {
            Move-Item -LiteralPath $backupPath -Destination $Destination -Force
        }
        else {
            Remove-Item -LiteralPath $backupPath -Force
        }
    }

    Copy-Item -LiteralPath $Source -Destination $newPath -Force

    $movedExisting = $false

    try {
        if (Test-Path -LiteralPath $Destination -PathType Leaf) {
            Move-Item -LiteralPath $Destination -Destination $backupPath -Force
            $movedExisting = $true
        }

        Move-Item -LiteralPath $newPath -Destination $Destination -Force

        if ($movedExisting -and (Test-Path -LiteralPath $backupPath -PathType Leaf)) {
            Remove-Item -LiteralPath $backupPath -Force
        }
    }
    catch {
        $installError = $_.Exception.Message

        Remove-Item -LiteralPath $newPath -Force -ErrorAction SilentlyContinue
        Remove-Item -LiteralPath $Destination -Force -ErrorAction SilentlyContinue

        if ($movedExisting -and (Test-Path -LiteralPath $backupPath -PathType Leaf)) {
            Move-Item -LiteralPath $backupPath -Destination $Destination -Force
        }

        throw "Could not install $Destination`: $installError"
    }
}

function Copy-FirstMatchingFile {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Root,

        [Parameter(Mandatory = $true)]
        [string[]]$Names,

        [Parameter(Mandatory = $true)]
        [string]$Destination
    )

    foreach ($name in $Names) {
        $match = Get-ChildItem `
            -LiteralPath $Root `
            -Recurse `
            -File `
            -ErrorAction SilentlyContinue |
            Where-Object { $_.Name -ieq $name } |
            Select-Object -First 1

        if ($null -ne $match) {
            Copy-Item -LiteralPath $match.FullName -Destination $Destination -Force
            return $true
        }
    }

    return $false
}

if (-not [Environment]::Is64BitOperatingSystem) {
    throw "The official Windows tool packages used by this downloader require 64-bit Windows."
}

if (-not (Test-Path -LiteralPath $DestinationFolder -PathType Container)) {
    throw "The GUI folder does not exist: $DestinationFolder"
}

$testFile = Join-Path $DestinationFolder (
    ".syybott-write-test-" + [guid]::NewGuid().ToString("N")
)

try {
    [System.IO.File]::WriteAllText($testFile, "write test")
}
catch {
    throw "The GUI folder is not writable. Move the GUI to a writable folder or run it with appropriate permissions."
}
finally {
    Remove-Item -LiteralPath $testFile -Force -ErrorAction SilentlyContinue
}

$tempRoot = Join-Path (
    [System.IO.Path]::GetTempPath()
) ("SYYBOTTS-Tool-Download-" + [guid]::NewGuid().ToString("N"))

[void](New-Item -ItemType Directory -Path $tempRoot -Force)

try {
    $webpZip = Join-Path $tempRoot "libwebp.zip"
    $ffmpegZip = Join-Path $tempRoot "ffmpeg.zip"
    $ffmpegChecksumFile = Join-Path $tempRoot "ffmpeg.zip.sha256"
    $webpExtract = Join-Path $tempRoot "libwebp"
    $ffmpegExtract = Join-Path $tempRoot "ffmpeg"

    $downloads = @(
        [pscustomobject]@{
            Label = "cwebp"
            Url = $WebPArchiveUrl
            Destination = $webpZip
        },
        [pscustomobject]@{
            Label = "FFmpeg"
            Url = $FFmpegArchiveUrl
            Destination = $ffmpegZip
        },
        [pscustomobject]@{
            Label = "FFmpeg checksum"
            Url = $FFmpegChecksumUrl
            Destination = $ffmpegChecksumFile
        }
    )

    Write-ToolStep "Starting parallel foreground downloads."
    Download-RequiredArchives -Downloads $downloads

    Write-Output "[STAGE] Verifying the FFmpeg SHA-256 checksum..."
    $checksumText = (Get-Content -LiteralPath $ffmpegChecksumFile -Raw).Trim()
    $checksumMatch = [regex]::Match($checksumText, '(?i)\b[a-f0-9]{64}\b')

    if (-not $checksumMatch.Success) {
        throw "The FFmpeg checksum response did not contain a valid SHA-256 value."
    }

    $expectedChecksum = $checksumMatch.Value.ToLowerInvariant()
    $actualChecksum = (
        Get-FileHash -LiteralPath $ffmpegZip -Algorithm SHA256
    ).Hash.ToLowerInvariant()

    if ($actualChecksum -ne $expectedChecksum) {
        throw "FFmpeg checksum verification failed. Nothing was installed."
    }

    Write-ToolStep "FFmpeg SHA-256 checksum verified."
    Write-Output "[STAGE] Extracting downloaded tool packages..."

    Expand-Archive -LiteralPath $webpZip -DestinationPath $webpExtract -Force
    Expand-Archive -LiteralPath $ffmpegZip -DestinationPath $ffmpegExtract -Force

    $cwebpCandidate = Get-ChildItem `
        -LiteralPath $webpExtract `
        -Recurse `
        -Filter "cwebp.exe" `
        -File |
        Select-Object -First 1

    $ffmpegCandidate = Get-ChildItem `
        -LiteralPath $ffmpegExtract `
        -Recurse `
        -Filter "ffmpeg.exe" `
        -File |
        Select-Object -First 1

    $ffprobeCandidate = Get-ChildItem `
        -LiteralPath $ffmpegExtract `
        -Recurse `
        -Filter "ffprobe.exe" `
        -File |
        Select-Object -First 1

    if ($null -eq $cwebpCandidate) {
        throw "cwebp.exe was not found in the downloaded WebP package."
    }

    if ($null -eq $ffmpegCandidate -or $null -eq $ffprobeCandidate) {
        throw "ffmpeg.exe or ffprobe.exe was not found in the downloaded FFmpeg package."
    }

    Write-Output "[STAGE] Validating downloaded executables..."

    $cwebpVersion = & $cwebpCandidate.FullName -version 2>&1 | Out-String
    if ($LASTEXITCODE -ne 0 -or [string]::IsNullOrWhiteSpace($cwebpVersion)) {
        throw "The downloaded cwebp.exe did not pass its version check."
    }

    $ffprobeVersion = & $ffprobeCandidate.FullName -version 2>&1 | Out-String
    if ($LASTEXITCODE -ne 0 -or $ffprobeVersion -notmatch '(?i)\bffprobe version\b') {
        throw "The downloaded ffprobe.exe did not pass its version check."
    }

    $encoderOutput = & $ffmpegCandidate.FullName -hide_banner -encoders 2>&1 | Out-String
    if ($LASTEXITCODE -ne 0) {
        throw "The downloaded ffmpeg.exe could not list its encoders."
    }

    if ($encoderOutput -notmatch '\blibx264\b') {
        throw "The downloaded FFmpeg build does not include libx264."
    }

    if ($encoderOutput -notmatch '(?m)^\s*[A-Z\.]{6}\s+aac\s') {
        throw "The downloaded FFmpeg build does not include AAC encoding."
    }

    Write-Output "[STAGE] Installing cwebp.exe, ffmpeg.exe, and ffprobe.exe..."

    Install-FileAtomic `
        -Source $cwebpCandidate.FullName `
        -Destination (Join-Path $DestinationFolder "cwebp.exe")

    Install-FileAtomic `
        -Source $ffmpegCandidate.FullName `
        -Destination (Join-Path $DestinationFolder "ffmpeg.exe")

    Install-FileAtomic `
        -Source $ffprobeCandidate.FullName `
        -Destination (Join-Path $DestinationFolder "ffprobe.exe")

    $licenseFolder = Join-Path $DestinationFolder "Third-Party-Licenses"
    [void](New-Item -ItemType Directory -Path $licenseFolder -Force)

    [void](Copy-FirstMatchingFile `
        -Root $webpExtract `
        -Names @("COPYING") `
        -Destination (Join-Path $licenseFolder "libwebp-COPYING.txt"))

    [void](Copy-FirstMatchingFile `
        -Root $webpExtract `
        -Names @("PATENTS") `
        -Destination (Join-Path $licenseFolder "libwebp-PATENTS.txt"))

    [void](Copy-FirstMatchingFile `
        -Root $webpExtract `
        -Names @("README.txt", "README") `
        -Destination (Join-Path $licenseFolder "libwebp-README.txt"))

    [void](Copy-FirstMatchingFile `
        -Root $ffmpegExtract `
        -Names @("LICENSE", "LICENSE.txt", "COPYING.GPLv3", "COPYING.GPLv2") `
        -Destination (Join-Path $licenseFolder "FFmpeg-LICENSE.txt"))

    [void](Copy-FirstMatchingFile `
        -Root $ffmpegExtract `
        -Names @("README.txt", "README") `
        -Destination (Join-Path $licenseFolder "FFmpeg-Gyan-Build-README.txt"))

    $thirdPartyNotice = @"
SYYBOTT'S MEDIA OPTIMIZER - THIRD-PARTY TOOLS

Downloaded: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')

cwebp / libwebp
Official Google WebP Windows package:
$WebPArchiveUrl

FFmpeg and FFprobe
FFmpeg release essentials Windows package:
$FFmpegArchiveUrl

Published FFmpeg SHA-256 checksum:
$FFmpegChecksumUrl

The FFmpeg download was verified against the checksum published by the build distributor before installation. See the retained license and build files in this directory.
"@

    $thirdPartyNotice |
        Set-Content `
            -LiteralPath (Join-Path $licenseFolder "THIRD-PARTY-NOTICES.txt") `
            -Encoding UTF8

    Write-Output "[STAGE] Finalizing tool installation..."
    Write-ToolStep "Tool installation completed successfully."
    Write-Output "[TOOLS INSTALLED]"
    exit 0
}
catch {
    Write-Output "[ERROR] $($_.Exception.Message)"
    exit 1
}
finally {
    Remove-Item -LiteralPath $tempRoot -Recurse -Force -ErrorAction SilentlyContinue
}
'@

    $source = $source.Replace(
        "__DESTINATION_LITERAL__",
        $destinationLiteral
    )
    $source = $source.Replace(
        "__GUI_VERSION_LITERAL__",
        $guiVersionLiteral
    )

    return $source
}

function Append-ActivityLine {
    param(
        [AllowEmptyString()]
        [string]$Line
    )

    $logTextBox.AppendText($Line + [System.Environment]::NewLine)
    $logTextBox.SelectionStart = $logTextBox.TextLength
    $logTextBox.ScrollToCaret()

    if ($Line -match '^\[DOWNLOAD\]\s+(\d+)%\s+\|\s+(.+)$') {
        $downloadPercent = [int]$Matches[1]
        $downloadDetails = $Matches[2]

        $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
        $progressBar.Minimum = 0
        $progressBar.Maximum = 100
        $progressBar.Value = [math]::Min(
            100,
            [math]::Max(0, $downloadPercent)
        )
        $statusLabel.Text = $downloadDetails
    }
    elseif ($Line -match '^\[DOWNLOAD\]\s+(.+?)\s+(\d+)%$') {
        $downloadLabel = $Matches[1]
        $downloadPercent = [int]$Matches[2]

        $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
        $progressBar.Minimum = 0
        $progressBar.Maximum = 100
        $progressBar.Value = [math]::Min(
            100,
            [math]::Max(0, $downloadPercent)
        )
        $statusLabel.Text = "Downloading $downloadLabel - $downloadPercent%"
    }
    elseif ($Line -match '^\[STAGE\]\s+(.+)$') {
        $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Marquee
        $progressBar.MarqueeAnimationSpeed = 30
        $statusLabel.Text = $Matches[1]
    }
    elseif ($Line -match '^\[(\d+)/(\d+)\s+\|\s+([^\]]+)\]\s*(.*)$') {
        $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
        $current = [int]$Matches[1]
        $total = [int]$Matches[2]

        if ($total -gt 0) {
            $progressBar.Maximum = $total
            $progressBar.Value = [math]::Min($current, $total)
        }

        $statusText = $Matches[4]
        if ([string]::IsNullOrWhiteSpace($statusText)) {
            $statusText = $Matches[3]
        }

        $statusLabel.Text = "$current / $total - $statusText"
    }
    elseif ($Line -match 'Report file:\s*(.+)$') {
        $possiblePath = $Matches[1].Trim()

        if (-not [string]::IsNullOrWhiteSpace($possiblePath)) {
            $script:LastReportPath = $possiblePath
        }
    }
    elseif ($Line -match 'Beginning (.+)\.\.\.') {
        $statusLabel.Text = $Line.Trim()
    }
}

function Read-NewWorkerOutput {
    param(
        [switch]$Final
    )

    if (
        [string]::IsNullOrWhiteSpace($script:OutputPath) -or
        -not (Test-Path -LiteralPath $script:OutputPath -PathType Leaf)
    ) {
        return
    }

    try {
        $stream = New-Object System.IO.FileStream(
            $script:OutputPath,
            [System.IO.FileMode]::Open,
            [System.IO.FileAccess]::Read,
            [System.IO.FileShare]::ReadWrite
        )

        try {
            [void]$stream.Seek(
                $script:OutputPosition,
                [System.IO.SeekOrigin]::Begin
            )

            $reader = New-Object System.IO.StreamReader(
                $stream,
                (New-Object System.Text.UTF8Encoding($false)),
                $true
            )

            try {
                $newText = $reader.ReadToEnd()
                $script:OutputPosition = $stream.Position
            }
            finally {
                $reader.Dispose()
            }
        }
        finally {
            $stream.Dispose()
        }

        if (-not [string]::IsNullOrEmpty($newText)) {
            $combined = $script:OutputRemainder + $newText
            $lines = $combined -split "`r?`n", -1

            if ($combined -match "(`r`n|`n)$") {
                $script:OutputRemainder = ""
                $completeLineCount = $lines.Count
            }
            else {
                $script:OutputRemainder = $lines[-1]
                $completeLineCount = $lines.Count - 1
            }

            for ($index = 0; $index -lt $completeLineCount; $index++) {
                $line = $lines[$index]
                if (
                    $script:CurrentRunCountsModify -and
                    $line -match '^\[(\d+)/(\d+)(?:\s|\|)'
                ) {
                    $processed = [long]$matches[1]
                    if ($processed -gt $script:CurrentModifyRunMaximum) {
                        $script:CurrentModifyRunMaximum = $processed
                        Save-ModifyProgress
                    }
                }
                Append-ActivityLine -Line $line
            }
        }

        if ($Final -and -not [string]::IsNullOrEmpty($script:OutputRemainder)) {
            if (
                $script:CurrentRunCountsModify -and
                $script:OutputRemainder -match '^\[(\d+)/(\d+)(?:\s|\|)'
            ) {
                $processed = [long]$matches[1]
                if ($processed -gt $script:CurrentModifyRunMaximum) {
                    $script:CurrentModifyRunMaximum = $processed
                }
            }
            Append-ActivityLine -Line $script:OutputRemainder
            $script:OutputRemainder = ""
        }
    }
    catch {
        Append-ActivityLine -Line "GUI OUTPUT-READ ERROR: $($_.Exception.Message)"
    }
}

function Find-LatestReport {
    if (-not (Test-Path -LiteralPath $LogsFolder -PathType Container)) {
        return ""
    }

    $filter = if ($script:CurrentMode -eq "Image") {
        "SYYBOTT-Media-Optimizer-Image-Report-*.txt"
    }
    else {
        "SYYBOTT-Media-Optimizer-Video-Report-*.txt"
    }

    $latest = Get-ChildItem `
        -LiteralPath $LogsFolder `
        -Filter $filter `
        -File `
        -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending |
        Select-Object -First 1

    if ($null -ne $latest) {
        return $latest.FullName
    }

    return ""
}

function Remove-RunFiles {
    if (
        -not [string]::IsNullOrWhiteSpace($script:RunDirectory) -and
        (Test-Path -LiteralPath $script:RunDirectory -PathType Container)
    ) {
        Remove-Item `
            -LiteralPath $script:RunDirectory `
            -Recurse `
            -Force `
            -ErrorAction SilentlyContinue
    }

    $script:RunDirectory = $null
    $script:OutputPath = $null
}

function Set-RunControls {
    param(
        [Parameter(Mandatory = $true)]
        [bool]$Running
    )

    $folderTextBox.Enabled = -not $Running
    $browseButton.Enabled = -not $Running
    $copyDestinationTextBox.Enabled = -not $Running
    $copyDestinationBrowseButton.Enabled = -not $Running
    $downloadToolsButton.Enabled = -not $Running
    $tabControl.Enabled = -not $Running
    $startButton.Enabled = $false
    $cancelButton.Enabled = $Running
    $exitButton.Enabled = -not $Running
    $openFolderButton.Enabled = -not $Running

    if ($Running) {
        $openReportButton.Enabled = $false
    }
    else {
        $openReportButton.Enabled = (
            -not [string]::IsNullOrWhiteSpace($script:LastReportPath) -and
            (Test-Path -LiteralPath $script:LastReportPath -PathType Leaf)
        )
        Update-StartAvailability
    }
}

function Complete-ToolDownload {
    if ($script:RunCompletionHandled) {
        return
    }

    $script:RunCompletionHandled = $true

    if ($null -ne $script:PollingTimer) {
        $script:PollingTimer.Stop()
    }

    Read-NewWorkerOutput -Final

    $exitCode = -1

    if ($null -ne $script:RunningProcess) {
        try {
            $script:RunningProcess.WaitForExit()
            $exitCode = $script:RunningProcess.ExitCode
        }
        catch {
            $exitCode = -1
        }

        $script:RunningProcess.Dispose()
        $script:RunningProcess = $null
    }

    $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
    $progressBar.MarqueeAnimationSpeed = 0
    [void](Update-ToolStatus)

    try {
        if ($script:CancelRequested) {
            Append-ActivityLine -Line ""
            Append-ActivityLine -Line "Tool download cancelled."
            $statusLabel.Text = "Tool download cancelled."
        }
        elseif ($exitCode -eq 0 -and (Test-AllRequiredTools)) {
            Append-ActivityLine -Line ""
            Append-ActivityLine -Line "Required tools are ready."
            $statusLabel.Text = "Required tools are ready."

            [void][System.Windows.Forms.MessageBox]::Show(
                "cwebp.exe, ffmpeg.exe, and ffprobe.exe are installed beside the app. Third-party license files were retained in the Third-Party-Licenses folder.",
                "Tools installed",
                [System.Windows.Forms.MessageBoxButtons]::OK,
                [System.Windows.Forms.MessageBoxIcon]::Information
            )

            [void](Ensure-MediaFolderConfigured)
        }
        else {
            Append-ActivityLine -Line ""
            Append-ActivityLine -Line "Tool installation failed. Review the activity log above."
            $statusLabel.Text = "Tool installation failed."
        }
    }
    finally {
        Disable-SleepPrevention
        Set-RunControls -Running $false
        Remove-RunFiles
        $script:CurrentOperation = ""
    }
}

function Complete-CurrentOperation {
    if ($script:CurrentOperation -eq "ToolDownload") {
        Complete-ToolDownload
    }
    else {
        Complete-OptimizationRun
    }
}

function Start-ToolDownload {
    if ($null -ne $script:RunningProcess) {
        return
    }

    if (-not [Environment]::Is64BitOperatingSystem) {
        Show-ErrorMessage -Message "The official Windows tool packages used by this downloader require 64-bit Windows."
        return
    }

    try {
        $script:CurrentOperation = "ToolDownload"
        $script:CancelRequested = $false
        $script:RunCompletionHandled = $false
        $script:OutputPosition = 0L
        $script:OutputRemainder = ""
        $script:LastReportPath = ""

        $logTextBox.Clear()
        $progressBar.Style = [System.Windows.Forms.ProgressBarStyle]::Blocks
        $progressBar.MarqueeAnimationSpeed = 0
        $progressBar.Minimum = 0
        $progressBar.Maximum = 100
        $progressBar.Value = 0
        $statusLabel.Text = "Preparing official tool downloads..."

        $script:RunDirectory = Join-Path (
            [System.IO.Path]::GetTempPath()
        ) ("SYYBOTTS-Tool-Installer-GUI-" + [guid]::NewGuid().ToString("N"))

        [void](New-Item -ItemType Directory -Path $script:RunDirectory -Force)

        $workerPath = Join-Path $script:RunDirectory "download-tools.ps1"
        $runnerPath = Join-Path $script:RunDirectory "run-download.cmd"
        $script:OutputPath = Join-Path $script:RunDirectory "tool-download-output.txt"

        $downloaderSource = Get-ToolDownloaderSource

        [System.IO.File]::WriteAllText(
            $workerPath,
            $downloaderSource,
            (New-Object System.Text.UTF8Encoding($true))
        )

        $powerShellPath = Join-Path $env:SystemRoot "System32\WindowsPowerShell\v1.0\powershell.exe"

        if (-not (Test-Path -LiteralPath $powerShellPath -PathType Leaf)) {
            $powerShellPath = (Get-Command powershell.exe -ErrorAction Stop).Source
        }

        $runnerContent = @"
@echo off
"$powerShellPath" -NoLogo -NoProfile -ExecutionPolicy Bypass -File "$workerPath" > "$script:OutputPath" 2>&1
exit /b %errorlevel%
"@

        [System.IO.File]::WriteAllText(
            $runnerPath,
            $runnerContent,
            [System.Text.Encoding]::ASCII
        )

        Append-ActivityLine -Line "Downloading required tools with parallel foreground BITS transfers."
        Append-ActivityLine -Line "Live progress includes downloaded size, transfer speed, and estimated time remaining."
        Append-ActivityLine -Line "The FFmpeg ZIP is verified before tools and licenses are installed beside the application."
        Append-ActivityLine -Line ""

        $processInfo = New-Object System.Diagnostics.ProcessStartInfo
        $processInfo.FileName = $env:ComSpec
        $processInfo.Arguments = '/d /s /c ""{0}""' -f $runnerPath
        $processInfo.UseShellExecute = $false
        $processInfo.CreateNoWindow = $true
        $processInfo.WorkingDirectory = $script:RunDirectory

        $script:RunningProcess = New-Object System.Diagnostics.Process
        $script:RunningProcess.StartInfo = $processInfo

        if (-not $script:RunningProcess.Start()) {
            throw "The tool-download worker could not be started."
        }

        Set-RunControls -Running $true
        $statusLabel.Text = "Downloading required tools..."

        $script:PollingTimer = New-Object System.Windows.Forms.Timer
        $script:PollingTimer.Interval = 250
        $script:PollingTimer.Add_Tick({
            Read-NewWorkerOutput

            if (
                $null -ne $script:RunningProcess -and
                $script:RunningProcess.HasExited
            ) {
                Complete-CurrentOperation
            }
        })
        $script:PollingTimer.Start()
    }
    catch {
        Set-RunControls -Running $false
        Remove-RunFiles
        $script:RunningProcess = $null
        $script:CurrentOperation = ""
        Show-ErrorMessage -Message $_.Exception.Message
        $statusLabel.Text = "Failed to start tool download."
    }
}

function Request-ToolDownload {
    $allFound = Test-AllRequiredTools

    $message = if ($allFound) {
@"
Download current copies of cwebp, FFmpeg, and FFprobe?

Existing tool files will be replaced only after the downloads pass validation. The FFmpeg archive is verified against the SHA-256 checksum published by the Windows build distributor.

The download is approximately 110 MB.
"@
    }
    else {
@"
Required optimizer tools are missing.

Download cwebp from the official Google WebP package and FFmpeg/FFprobe from the FFmpeg-linked gyan.dev Windows release essentials package?

The FFmpeg archive is verified against its published SHA-256 checksum. The download is approximately 110 MB.
"@
    }

    $answer = [System.Windows.Forms.MessageBox]::Show(
        $message,
        $(if ($allFound) { "Update required tools" } else { "Download required tools" }),
        [System.Windows.Forms.MessageBoxButtons]::YesNo,
        [System.Windows.Forms.MessageBoxIcon]::Information,
        [System.Windows.Forms.MessageBoxDefaultButton]::Button1
    )

    if ($answer -eq [System.Windows.Forms.DialogResult]::Yes) {
        Start-ToolDownload
    }
}

function Show-TestCompletionSummary {
    $text = $logTextBox.Text
    if ($script:CurrentMode -eq "Image") {
        $values = @{}
        $matches = [regex]::Matches(
            $text,
            '(?ms)Quality\s+(\d+):.*?Size reduction:\s+([0-9.,]+)%'
        )
        foreach ($match in $matches) {
            $quality = $match.Groups[1].Value
            $number = 0.0
            if ([double]::TryParse(
                $match.Groups[2].Value,
                [Globalization.NumberStyles]::Number,
                [Globalization.CultureInfo]::CurrentCulture,
                [ref]$number
            )) {
                if (-not $values.ContainsKey($quality)) {
                    $values[$quality] = [Collections.Generic.List[double]]::new()
                }
                $values[$quality].Add($number)
            }
        }
        $lines = [Collections.Generic.List[string]]::new()
        $highestQuality = $null
        $highestAverage = -1.0
        foreach ($quality in @($values.Keys | Sort-Object -Descending)) {
            $average = ($values[$quality] | Measure-Object -Average).Average
            if ($average -gt $highestAverage) {
                $highestAverage = $average
                $highestQuality = $quality
            }
            [void]$lines.Add(
                ("Quality {0}: {1:N1}% average savings across {2} image{3}" -f
                $quality,
                $average,
                $values[$quality].Count,
                $(if ($values[$quality].Count -eq 1) { "" } else { "s" }))
            )
        }
        if ($lines.Count -eq 0) { [void]$lines.Add("No smaller test images were retained.") }
        elseif ($null -ne $highestQuality) {
            [void]$lines.Add("")
            [void]$lines.Add("Highest measured savings: Quality $highestQuality")
        }
        $message = ($lines -join "`r`n") +
            "`r`n`r`nReview the test images on the target device before completing a full library conversion."
        [void][Windows.Forms.MessageBox]::Show(
            $message, "Image test results",
            [Windows.Forms.MessageBoxButtons]::OK,
            [Windows.Forms.MessageBoxIcon]::Information
        )
        $openFolderButton.Text = "Open Test Images"
    }
    else {
        $resultLines = New-Object System.Collections.Generic.List[string]
        $matches = [regex]::Matches(
            $text,
            '(?ms)Test setting:\s*(.+?)\r?\n.*?Size reduction:\s+([0-9.,]+)%'
        )

        foreach ($match in $matches) {
            [void]$resultLines.Add(
                ("{0}: {1}% storage saved" -f
                $match.Groups[1].Value.Trim(),
                $match.Groups[2].Value)
            )
        }

        $result = if ($resultLines.Count -gt 0) {
            $resultLines -join "`r`n"
        }
        else {
            "No smaller test videos were retained."
        }

        [void][Windows.Forms.MessageBox]::Show(
            $result + "`r`n`r`nReview the videos for playback and audio issues on the target device before completing a full library conversion.",
            "Video test results",
            [Windows.Forms.MessageBoxButtons]::OK,
            [Windows.Forms.MessageBoxIcon]::Information
        )
        $openFolderButton.Text = "Open Test Videos"
    }
}

function Complete-OptimizationRun {
    if ($script:RunCompletionHandled) {
        return
    }

    $script:RunCompletionHandled = $true

    if ($null -ne $script:PollingTimer) {
        $script:PollingTimer.Stop()
    }

    Read-NewWorkerOutput -Final

    $exitCode = -1

    if ($null -ne $script:RunningProcess) {
        try {
            $script:RunningProcess.WaitForExit()
            $exitCode = $script:RunningProcess.ExitCode
        }
        catch {
            $exitCode = -1
        }

        $script:RunningProcess.Dispose()
        $script:RunningProcess = $null
    }

    if (
        -not $script:CurrentRunIsTest -and
        (
            [string]::IsNullOrWhiteSpace($script:LastReportPath) -or
            -not (
                Test-Path `
                    -LiteralPath $script:LastReportPath `
                    -PathType Leaf
            )
        )
    ) {
        $script:LastReportPath = Find-LatestReport
    }

    try {
        if ($script:CancelRequested) {
            Append-ActivityLine -Line ""
            Append-ActivityLine -Line "Cancelled by user. Review the activity log and generated report for the final file state."
            $statusLabel.Text = "Cancelled."
        }
        elseif ($exitCode -eq 0) {
            if ($script:CurrentRunIsTest) {
                $statusLabel.Text = "Test finished."
                Show-TestCompletionSummary
            }
            else {
                $statusLabel.Text = "Finished."
            }
        }
        else {
            Append-ActivityLine -Line ""
            Append-ActivityLine -Line "Worker exited with code $exitCode."
            $statusLabel.Text = "Finished with an error."
        }

        if ($progressBar.Maximum -gt 0 -and -not $script:CancelRequested) {
            $progressBar.Value = $progressBar.Maximum
        }
    }
    finally {
        Save-ModifyProgress -Force
        Disable-SleepPrevention
        Set-RunControls -Running $false
        Remove-RunFiles
        $script:CurrentOperation = ""
        $script:CurrentRunCountsModify = $false
    }
}

function Update-StartAvailability {
    if ($null -ne $script:RunningProcess) {
        $startButton.Enabled = $false
        return
    }
    if ($tabControl.SelectedIndex -eq 0) {
        $startButton.Enabled = (
            $imageTestCheckBox.Checked -or
            -not [string]::IsNullOrWhiteSpace(
                [string]$imageOperationCombo.Tag
            )
        )
    }
    elseif ($tabControl.SelectedIndex -eq 1) {
        $startButton.Enabled = (
            $videoTestCheckBox.Checked -or
            -not [string]::IsNullOrWhiteSpace(
                [string]$videoOperationCombo.Tag
            )
        )
    }
    else {
        $startButton.Enabled = $false
    }
}

function Set-OperationSelection {
    param(
        [Parameter(Mandatory = $true)]
        [ValidateSet("Image", "Video")]
        [string]$Mode,

        [AllowEmptyString()]
        [string]$Selection
    )
    $combo = if ($Mode -eq "Image") {
        $imageOperationCombo
    } else {
        $videoOperationCombo
    }
    $info = if ($Mode -eq "Image") {
        $imageOperationInfoLabel
    } else {
        $videoOperationInfoLabel
    }
    $combo.Items.Clear()
    if ([string]::IsNullOrWhiteSpace($Selection)) {
        [void]$combo.Items.Add("Select operation mode...")
        $combo.Tag = ""
        $info.Text = ""
    }
    else {
        [void]$combo.Items.Add($Selection)
        $combo.Tag = $Selection
        if ($Selection -eq "Copy") {
            $destination = $copyDestinationTextBox.Text.Trim()
            $info.Text = if ([string]::IsNullOrWhiteSpace($destination)) {
                "Creates a new media library. The existing library remains unchanged."
            } else {
                "New library: $destination"
            }
        }
        else {
            $info.Text = "Optimizes the existing media library directly."
        }
    }
    $combo.SelectedIndex = 0
    Write-DiagnosticLog `
        -Category "OPTION" `
        -Message "$Mode operation selection set to '$Selection'."
    Write-DiagnosticApplicationState `
        -Reason "$Mode operation selection changed"
    Update-StartAvailability
}

function Show-OperationModeSelector {
    param(
        [Parameter(Mandatory = $true)]
        [ValidateSet("Image", "Video")]
        [string]$Mode,

        [switch]$DiagnosticLayoutOnly
    )
    Write-DiagnosticLog `
        -Category "POPUP" `
        -Message "Preparing $Mode operation-mode chooser."
    Write-DiagnosticControlSnapshot `
        -Reason "Before $Mode operation-mode chooser"

    $dialog = New-Object Windows.Forms.Form
    $dialog.Text = "$Mode operation mode"
    $dialog.StartPosition = "CenterParent"
    $dialog.FormBorderStyle = "FixedDialog"
    $dialog.MaximizeBox = $false
    $dialog.MinimizeBox = $false
    $dialog.AutoScaleMode = [Windows.Forms.AutoScaleMode]::None
    $dialog.ClientSize = New-Object Drawing.Size(620, 370)
    $dialog.MinimumSize = New-Object Drawing.Size(636, 409)
    $dialog.Font = New-Object Drawing.Font(
        "Segoe UI",
        12,
        [Drawing.FontStyle]::Regular,
        [Drawing.GraphicsUnit]::Pixel
    )

    $heading = New-Object Windows.Forms.Label
    $heading.Text = "Choose how the $($Mode.ToLowerInvariant()) library should be processed:"
    $heading.Location = New-Object Drawing.Point(22, 20)
    $heading.Size = New-Object Drawing.Size(576, 34)
    $heading.Font = New-Object Drawing.Font(
        "Segoe UI Semibold",
        16,
        [Drawing.FontStyle]::Regular,
        [Drawing.GraphicsUnit]::Pixel
    )
    $dialog.Controls.Add($heading)

    $copyRadio = New-Object Windows.Forms.RadioButton
    $copyRadio.Text = "Copy"
    $copyRadio.Location = New-Object Drawing.Point(26, 70)
    $copyRadio.Size = New-Object Drawing.Size(120, 28)
    $dialog.Controls.Add($copyRadio)

    $copyDescription = New-Object Windows.Forms.Label
    $copyDescription.Text = "Creates a separate optimized media library in a destination you choose. The existing library remains unchanged."
    $copyDescription.Location = New-Object Drawing.Point(56, 104)
    $copyDescription.Size = New-Object Drawing.Size(536, 62)
    $dialog.Controls.Add($copyDescription)

    $modifyRadio = New-Object Windows.Forms.RadioButton
    $modifyRadio.Text = "Modify"
    $modifyRadio.Location = New-Object Drawing.Point(26, 182)
    $modifyRadio.Size = New-Object Drawing.Size(120, 28)
    $dialog.Controls.Add($modifyRadio)

    $modifyDescription = New-Object Windows.Forms.Label
    $modifyDescription.Text = "Optimizes the existing media library directly. Valid replacements may permanently replace or remove original files."
    $modifyDescription.Location = New-Object Drawing.Point(56, 216)
    $modifyDescription.Size = New-Object Drawing.Size(536, 62)
    $dialog.Controls.Add($modifyDescription)

    $current = if ($Mode -eq "Image") {
        [string]$imageOperationCombo.Tag
    } else {
        [string]$videoOperationCombo.Tag
    }
    if ($current -eq "Copy") { $copyRadio.Checked = $true }
    elseif ($current -eq "Modify") { $modifyRadio.Checked = $true }

    $continueButton = New-Object Windows.Forms.Button
    $continueButton.Text = "Continue"
    $continueButton.Location = New-Object Drawing.Point(404, 316)
    $continueButton.Size = New-Object Drawing.Size(94, 34)
    $continueButton.Anchor = "Bottom,Right"
    $dialog.Controls.Add($continueButton)

    $cancelButtonLocal = New-Object Windows.Forms.Button
    $cancelButtonLocal.Text = "Cancel"
    $cancelButtonLocal.Location = New-Object Drawing.Point(506, 316)
    $cancelButtonLocal.Size = New-Object Drawing.Size(94, 34)
    $cancelButtonLocal.Anchor = "Bottom,Right"
    $cancelButtonLocal.DialogResult = [Windows.Forms.DialogResult]::Cancel
    $dialog.Controls.Add($cancelButtonLocal)
    $dialog.CancelButton = $cancelButtonLocal
    $dialog.AcceptButton = $continueButton

    [double]$dialogScaleFactor = [math]::Max(
        1.0,
        $script:DisplayScaleFactor
    )

    if ($dialogScaleFactor -gt 1.01) {
        Scale-ControlTreeOnce `
            -RootControl $dialog `
            -ScaleFactor $dialogScaleFactor
    }

    if ($DiagnosticLayoutOnly) {
        try {
            return @(
                Get-DiagnosticLayoutIssues `
                    -RootControl $dialog `
                    -IncludeHidden
            )
        }
        finally {
            $dialog.Dispose()
        }
    }

    $continueButton.Add_Click({
        if (-not $copyRadio.Checked -and -not $modifyRadio.Checked) {
            [void][Windows.Forms.MessageBox]::Show(
                "Select Copy or Modify.",
                "Operation mode",
                [Windows.Forms.MessageBoxButtons]::OK,
                [Windows.Forms.MessageBoxIcon]::Information
            )
            return
        }
        $dialog.Tag = if ($copyRadio.Checked) { "Copy" } else { "Modify" }
        $dialog.DialogResult = [Windows.Forms.DialogResult]::OK
        $dialog.Close()
    })

    try {
        Write-DiagnosticControlSnapshot `
            -RootControl $dialog `
            -Reason "$Mode operation-mode chooser ready"
        Write-DiagnosticLog `
            -Category "POPUP" `
            -Message "Opening $Mode operation-mode chooser."

        $dialogResult = $dialog.ShowDialog($form)
        if ($dialogResult -ne [Windows.Forms.DialogResult]::OK) {
            Write-DiagnosticLog `
                -Category "POPUP" `
                -Message "$Mode operation-mode chooser cancelled."
            return
        }
        $selection = [string]$dialog.Tag
        Write-DiagnosticLog `
            -Category "POPUP" `
            -Message "$Mode operation-mode chooser selected '$selection'."
    }
    finally {
        Write-DiagnosticControlSnapshot `
            -RootControl $dialog `
            -Reason "$Mode operation-mode chooser closed"
        $dialog.Dispose()
        Write-DiagnosticControlSnapshot `
            -Reason "After $Mode operation-mode chooser"
        Write-DiagnosticApplicationState `
            -Reason "After $Mode operation-mode chooser"
    }

    if ($selection -eq "Copy" -and -not (Select-CopyDestination)) {
        Write-DiagnosticLog `
            -Category "OPTION" `
            -Message (
                "$Mode Copy destination selection was cancelled; " +
                "restoring '$current'."
            )
        Set-OperationSelection -Mode $Mode -Selection $current
        return
    }
    Set-OperationSelection -Mode $Mode -Selection $selection
}

function Select-CopyDestination {
    $dialog = New-Object Windows.Forms.FolderBrowserDialog
    $dialog.Description = "Choose where the optimized library will be built"
    $dialog.ShowNewFolderButton = $true
    $savedDestination = $copyDestinationTextBox.Text.Trim()
    if (
        -not [string]::IsNullOrWhiteSpace($savedDestination) -and
        (Test-Path -LiteralPath $savedDestination -PathType Container)
    ) {
        $dialog.SelectedPath = $savedDestination
    }
    try {
        if ($dialog.ShowDialog($form) -eq [Windows.Forms.DialogResult]::OK) {
            $copyDestinationTextBox.Text = [IO.Path]::GetFullPath($dialog.SelectedPath)
            [void](Save-ApplicationSettings `
                -MediaFolder $folderTextBox.Text `
                -CopyDestination $copyDestinationTextBox.Text)
            return $true
        }
        Write-DiagnosticLog `
            -Category "OPTION" `
            -Message "Copy destination picker cancelled."
    }
    finally { $dialog.Dispose() }
    return $false
}

