    $ok = New-Object Windows.Forms.Button
    $ok.Text = "Continue"
    $ok.Location = New-Object Drawing.Point(252, 157)
    $ok.Size = New-Object Drawing.Size(85, 30)
    $ok.DialogResult = [Windows.Forms.DialogResult]::OK
    $dialog.Controls.Add($ok)

    $cancel = New-Object Windows.Forms.Button
    $cancel.Text = "Cancel"
    $cancel.Location = New-Object Drawing.Point(347, 157)
    $cancel.Size = New-Object Drawing.Size(85, 30)
    $cancel.DialogResult = [Windows.Forms.DialogResult]::Cancel
    $dialog.Controls.Add($cancel)
    $dialog.AcceptButton = $ok
    $dialog.CancelButton = $cancel

    try {
        if ($dialog.ShowDialog($form) -ne [Windows.Forms.DialogResult]::OK) {
            return $null
        }
        $policy = @("Skip", "ReplaceSmaller", "Rebuild")[$combo.SelectedIndex]
        return [pscustomobject]@{ Policy = $policy; Verify = $verify.Checked }
    }
    finally { $dialog.Dispose() }
}

function Start-CopyModeRun {
    param([ValidateSet("Image", "Video")][string]$Mode)

    $script:CurrentRunCountsModify = $false
    $source = $folderTextBox.Text.Trim()
    $destination = $copyDestinationTextBox.Text.Trim()
    if (-not (Test-Path -LiteralPath $source -PathType Container)) {
        Show-ErrorMessage -Message "Select a valid source library folder."
        return
    }
    if ([string]::IsNullOrWhiteSpace($destination)) {
        if (-not (Select-CopyDestination)) { return }
        $destination = $copyDestinationTextBox.Text.Trim()
    }
    $source = [IO.Path]::GetFullPath($source).TrimEnd('\')
    $destination = [IO.Path]::GetFullPath($destination).TrimEnd('\')
    $sourcePrefix = $source + '\'
    $destinationPrefix = $destination + '\'
    if (
        $destination.StartsWith($sourcePrefix, [StringComparison]::OrdinalIgnoreCase) -or
        $source.StartsWith($destinationPrefix, [StringComparison]::OrdinalIgnoreCase) -or
        $source -ieq $destination
    ) {
        Show-ErrorMessage -Message "The source and Copy Mode destination cannot contain one another."
        return
    }

    $options = Read-CopyModeOptions
    if ($null -eq $options) { return }
    if (
        $options.Policy -eq "Rebuild" -and
        (Test-Path -LiteralPath $destination -PathType Container) -and
        -not $script:DisableWarnings
    ) {
        $confirmation = [Windows.Forms.MessageBox]::Show(
            "REBUILD DESTINATION?`r`n`r`nEvery file and folder currently inside the destination will be permanently deleted. The source library will not be changed.",
            "Final destination rebuild confirmation",
            [Windows.Forms.MessageBoxButtons]::YesNo,
            [Windows.Forms.MessageBoxIcon]::Warning,
            [Windows.Forms.MessageBoxDefaultButton]::Button2
        )
        if ($confirmation -ne [Windows.Forms.DialogResult]::Yes) { return }
    }

    if (-not (Enable-SleepPrevention)) {
        Show-ErrorMessage -Message "Windows did not accept the request to prevent sleep."
        return
    }

    try {
        [void](Save-ApplicationSettings -MediaFolder $source -CopyDestination $destination)
        $script:CurrentOperation = "CopyMode"
        $script:CurrentMode = $Mode
        $script:CurrentTargetFolder = $source
        $script:CurrentRunIsTest = $false
        $script:CurrentCopyDestination = $destination
        $openFolderButton.Text = "Open Destination"
        $script:LastReportPath = ""
        $script:CancelRequested = $false
        $script:RunCompletionHandled = $false
        $script:OutputPosition = 0L
        $script:OutputRemainder = ""
        $logTextBox.Clear()
        $statusLabel.Text = "Preparing Copy Mode..."
        $progressBar.Minimum = 0
        $progressBar.Maximum = 100
        $progressBar.Value = 0

        $script:RunDirectory = Join-Path ([IO.Path]::GetTempPath()) (
            "SYYBOTTS-Copy-Mode-" + [guid]::NewGuid().ToString("N")
        )
        [void](New-Item -ItemType Directory -Path $script:RunDirectory -Force)
        $workerPath = Join-Path $script:RunDirectory "copy-worker.ps1"
        $runnerPath = Join-Path $script:RunDirectory "run-copy-worker.cmd"
        $script:OutputPath = Join-Path $script:RunDirectory "worker-output.txt"
        [IO.File]::WriteAllText(
            $workerPath,
            (Get-EmbeddedCopyWorkerSource),
            (New-Object Text.UTF8Encoding($true))
        )

        function Quote-Arg([string]$value) {
            return '"' + $value.Replace('"', '\"') + '"'
        }
        $arguments = @(
            "-Mode", (Quote-Arg $Mode),
            "-SourceRoot", (Quote-Arg $source),
            "-DestinationRoot", (Quote-Arg $destination),
            "-Policy", (Quote-Arg $options.Policy),
            "-LogsRoot", (Quote-Arg $LogsFolder),
            "-CwebpPath", (Quote-Arg (Get-RequiredToolPath "cwebp.exe")),
            "-FfmpegPath", (Quote-Arg (Get-RequiredToolPath "ffmpeg.exe")),
            "-FfprobePath", (Quote-Arg (Get-RequiredToolPath "ffprobe.exe")),
            "-PngCompression", [string][int]$pngCompressionNumeric.Value,
            "-PngHandling", [string]($pngHandlingCombo.SelectedIndex + 1),
            "-JpegQuality", [string][int]$jpegQualityNumeric.Value,
            "-JpegHandling", [string]($jpegHandlingCombo.SelectedIndex + 1),
            "-VideoProfile", [string](Get-SelectedVideoProfileChoice),
            "-EncoderMode", [string]$encoderModeCombo.SelectedIndex
        )
        if ($options.Verify) { $arguments += "-VerifyDestination" }
        $powerShellPath = Join-Path $env:SystemRoot "System32\WindowsPowerShell\v1.0\powershell.exe"
        $runnerContent = '@echo off' + "`r`n" +
            '"' + $powerShellPath + '" -NoLogo -NoProfile -ExecutionPolicy Bypass -File "' +
            $workerPath + '" ' + ($arguments -join " ") + ' > "' + $script:OutputPath +
            '" 2>&1' + "`r`nexit /b %errorlevel%`r`n"
        [IO.File]::WriteAllText($runnerPath, $runnerContent, [Text.Encoding]::ASCII)

        Append-ActivityLine "Version $GuiVersion"
        Append-ActivityLine "Copy Mode: $Mode"
        Append-ActivityLine "Source: $source"
        Append-ActivityLine "Destination: $destination"
        Append-ActivityLine ""

        $psi = New-Object Diagnostics.ProcessStartInfo
        $psi.FileName = $env:ComSpec
        $psi.Arguments = '/d /s /c ""{0}""' -f $runnerPath
        $psi.UseShellExecute = $false
        $psi.CreateNoWindow = $true
        $psi.WorkingDirectory = $script:RunDirectory
        $script:RunningProcess = New-Object Diagnostics.Process
        $script:RunningProcess.StartInfo = $psi
        if (-not $script:RunningProcess.Start()) { throw "Copy Mode worker could not start." }
        Set-RunControls -Running $true
        $script:PollingTimer = New-Object Windows.Forms.Timer
        $script:PollingTimer.Interval = 250
        $script:PollingTimer.Add_Tick({
            Read-NewWorkerOutput
            if ($null -ne $script:RunningProcess -and $script:RunningProcess.HasExited) {
                Complete-OptimizationRun
            }
        })
        $script:PollingTimer.Start()
    }
    catch {
        Disable-SleepPrevention
        Remove-RunFiles
        Set-RunControls -Running $false
        Show-ErrorMessage -Message "Copy Mode could not start.`r`n`r`n$($_.Exception.Message)"
    }
}

function Start-OptimizationRun {
    $targetFolder = $folderTextBox.Text.Trim()

    if (
        [string]::IsNullOrWhiteSpace($targetFolder) -or
        -not (Test-Path -LiteralPath $targetFolder -PathType Container)
    ) {
        Show-ErrorMessage -Message "Select a valid library folder."
        return
    }

    $targetFolder = [System.IO.Path]::GetFullPath($targetFolder)
    $folderTextBox.Text = $targetFolder
    $openFolderButton.Text = "Open Folder"
    $script:CurrentCopyDestination = ""
    [void](Save-MediaFolderSetting -MediaFolder $targetFolder)

    $mode = if ($tabControl.SelectedIndex -eq 0) {
        "Image"
    }
    else {
        "Video"
    }

    $operationMode = if ($mode -eq "Image") {
        [string]$imageOperationCombo.Tag
    } else {
        [string]$videoOperationCombo.Tag
    }

    $testSelected = if ($mode -eq "Image") {
        $imageTestCheckBox.Checked
    } else {
        $videoTestCheckBox.Checked
    }

    if (
        [string]::IsNullOrWhiteSpace($operationMode) -and
        -not $testSelected
    ) {
        Show-ErrorMessage -Message "Choose Copy or Modify before starting."
        return
    }

    if ($operationMode -eq "Copy" -and -not $testSelected) {
        Start-CopyModeRun -Mode $mode
        return
    }

    $script:CurrentRunIsTest = $testSelected
    $script:CurrentRunCountsModify = (
        $operationMode -eq "Modify" -and
        -not $testSelected -and
        -not $script:DiagnosticSelfTestActive
    )
    $script:CurrentModifyRunMaximum = 0L
    $script:LastSavedModifyRunMaximum = 0L

    $script:CurrentTestOutputFolder = if (
        $script:CurrentRunIsTest -and
        $mode -eq "Image"
    ) {
        Join-Path $ApplicationRoot "Test Images"
    }
    elseif ($script:CurrentRunIsTest) {
        Join-Path $ApplicationRoot "Test Videos"
    }
    else {
        ""
    }

    $cwebpPath = Get-RequiredToolPath -Name "cwebp.exe"
    $ffmpegPath = Get-RequiredToolPath -Name "ffmpeg.exe"
    $ffprobePath = Get-RequiredToolPath -Name "ffprobe.exe"

    if ($mode -eq "Image" -and -not (Test-Path -LiteralPath $cwebpPath -PathType Leaf)) {
        Show-ErrorMessage -Message "cwebp.exe is missing. Click Download Tools to install it automatically."
        return
    }

    if ($mode -eq "Video") {
        if (-not (Test-Path -LiteralPath $ffmpegPath -PathType Leaf)) {
            Show-ErrorMessage -Message "ffmpeg.exe is missing. Click Download Tools to install it automatically."
            return
        }

        if (-not (Test-Path -LiteralPath $ffprobePath -PathType Leaf)) {
            Show-ErrorMessage -Message "ffprobe.exe is missing. Click Download Tools to install it automatically."
            return
        }
    }

    $warningTitle = "Permanent file replacement warning"

    if ($mode -eq "Image" -and $imageTestCheckBox.Checked) {
        $warningTitle = "JPG/JPEG Test"
        $warning = @"
Creates WebP comparisons for up to $($imageTestCountCombo.SelectedItem) images.

Originals are not changed. Searches the selected folder and up to two subfolder levels. Existing test files are reused; equal or larger outputs are discarded.

Outputs are saved in Test Images beside the app.

Proceed?
"@
    }
    elseif ($mode -eq "Video" -and $videoTestCheckBox.Checked) {
        $warningTitle = "Video Test"
        $videoTestDescription = if ($script:AdvancedVideoProfilesEnabled) {
            "Creates one MP4 comparison using the selected advanced encoding."
        } else {
            "Creates four MP4 comparisons using Default and Super Light with both encoder modes."
        }
        $warning = @"
$videoTestDescription

The original is not changed. Searches the selected folder and up to two subfolder levels. Existing test files are reused; equal or larger outputs are discarded.

Outputs are saved in Test Videos beside the app.

Proceed?
"@
    }
    elseif ($mode -eq "Image") {
        if (
            $pngHandlingCombo.SelectedIndex -eq 0 -and
            $jpegHandlingCombo.SelectedIndex -eq 0
        ) {
            Show-ErrorMessage -Message "Choose at least one image format to process in Modify mode."
            return
        }

        switch ($jpegHandlingCombo.SelectedIndex) {
            1 {
                $pngDeletionSentence = if ($pngHandlingCombo.SelectedIndex -eq 0) {
                    "PNG files are left untouched."
                } else {
                    "PNG files may participate in duplicate cleanup."
                }
                $warning = @"
All JPG/JPEG processing is enabled.

Standalone JPG/JPEG files are compared with their generated WebP. Duplicate-name groups are consolidated to the smallest valid WebP. $pngDeletionSentence Original files selected for replacement are permanently deleted and bypass the Recycle Bin.

Transparent PNG groups are protected from lossy or nontransparent replacements.

Back up the library first and test a copied sample folder before processing the full library.

Proceed?
"@
            }
            default {
                $warning = @"
PNG originals will be permanently deleted after a valid lossless WebP is created. Existing source/WebP pairs are cleaned automatically. Deleted files bypass the Recycle Bin.

Proceed?
"@
            }
        }
    }
    else {
        $warning = @"
A source video is permanently deleted only after a smaller MP4 output passes validation. Deleted files bypass the Recycle Bin.

Back up the library before processing whenever possible.

Proceed?
"@
    }

    if (
        $mode -eq "Video" -and
        $videoTestCheckBox.Checked -and
        $script:AdvancedVideoProfilesEnabled -and
        [string]::IsNullOrWhiteSpace((Get-SelectedVideoTestPlan))
    ) {
        Show-ErrorMessage -Message "Select an encoding for the video test."
        return
    }

    if (-not (Show-WarningConfirmation -Message $warning -Title $warningTitle)) {
        return
    }

    if (-not (Enable-SleepPrevention)) {
        Show-ErrorMessage -Message "Windows did not accept the request to prevent sleep. The run was not started."
        return
    }

    try {
        $script:CurrentOperation = "Optimization"
        $script:CurrentMode = $mode
        $script:CurrentTargetFolder = (Get-Item -LiteralPath $targetFolder).FullName
        $script:LastReportPath = ""
        $script:CancelRequested = $false
        $script:RunCompletionHandled = $false
        $script:OutputPosition = 0L
        $script:OutputRemainder = ""

        $logTextBox.Clear()
        $progressBar.Minimum = 0
        $progressBar.Maximum = 100
        $progressBar.Value = 0
        $statusLabel.Text = "Preparing worker..."

        $script:RunDirectory = Join-Path (
            [System.IO.Path]::GetTempPath()
        ) ("SYYBOTTS-Media-Optimizer-GUI-" + [guid]::NewGuid().ToString("N"))

        [void](New-Item -ItemType Directory -Path $script:RunDirectory -Force)

        $workerPath = Join-Path $script:RunDirectory "worker.ps1"
        $answersPath = Join-Path $script:RunDirectory "answers.txt"
        $runnerPath = Join-Path $script:RunDirectory "run-worker.cmd"
        $script:OutputPath = Join-Path $script:RunDirectory "worker-output.txt"

        $engineSource = Get-EmbeddedEngineSource
        $targetLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $script:CurrentTargetFolder
        $reportRootLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $LogsFolder
        $cwebpLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $cwebpPath
        $ffmpegLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $ffmpegPath
        $ffprobeLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $ffprobePath

        $workerSource = (
            '[Console]::OutputEncoding = New-Object System.Text.UTF8Encoding($false)' +
            [Environment]::NewLine +
            $engineSource
        )

        $workerSource = $workerSource.Replace(
            '$cwebp = Join-Path $PSScriptRoot "cwebp.exe"',
            ('$cwebp = ' + $cwebpLiteral)
        )
        $workerSource = $workerSource.Replace(
            '$ffmpeg = Join-Path $PSScriptRoot "ffmpeg.exe"',
            ('$ffmpeg = ' + $ffmpegLiteral)
        )
        $workerSource = $workerSource.Replace(
            '$ffprobe = Join-Path $PSScriptRoot "ffprobe.exe"',
            ('$ffprobe = ' + $ffprobeLiteral)
        )
        $workerSource = $workerSource.Replace(
            '$targetFolder = $PSScriptRoot',
            ('$targetFolder = ' + $targetLiteral)
        )
        $workerSource = $workerSource.Replace(
            '$script:ReportRoot = Join-Path $PSScriptRoot "Logs"',
            ('$script:ReportRoot = ' + $reportRootLiteral)
        )
        $testOutputRootLiteral = Convert-ToPowerShellSingleQuotedLiteral -Value $ApplicationRoot
        $workerSource = $workerSource.Replace(
            '$script:TestOutputRoot = $PSScriptRoot',
            ('$script:TestOutputRoot = ' + $testOutputRootLiteral)
        )

        $workerSource = $workerSource.Replace(
            '$script:RunAgain = Read-EndAction',
            '$script:RunAgain = $false'
        )

        [System.IO.File]::WriteAllText(
            $workerPath,
            $workerSource,
            (New-Object System.Text.UTF8Encoding($true))
        )

        $answers = New-Object System.Collections.Generic.List[string]

        if ($mode -eq "Image") {
            [void]$answers.Add("1")

            if ($imageTestCheckBox.Checked) {
                [void]$answers.Add("2")
                [void]$answers.Add(
                    [string]($imageTestCountCombo.SelectedIndex + 1)
                )
                $imageTestQualityMode = (
                    $imageTestQualityCombo.SelectedIndex + 1
                )
                [void]$answers.Add([string]$imageTestQualityMode)

                if ($imageTestQualityMode -eq 2) {
                    [void]$answers.Add(
                        [string][int]$imageTestCustomNumeric.Value
                    )
                }

                [void]$answers.Add("2")
            }
            else {
                [void]$answers.Add("1")
                [void]$answers.Add(
                    [string]($pngHandlingCombo.SelectedIndex + 1)
                )
                $jpegHandlingChoice = (
                    $jpegHandlingCombo.SelectedIndex + 1
                )
                [void]$answers.Add([string]$jpegHandlingChoice)

                if ($jpegHandlingChoice -gt 1) {
                    [void]$answers.Add("y")
                }

                if ($pngHandlingCombo.SelectedIndex -gt 0) {
                    [void]$answers.Add(
                        [string][int]$pngCompressionNumeric.Value
                    )
                }

                if ($jpegHandlingChoice -gt 1) {
                    [void]$answers.Add(
                        [string][int]$jpegQualityNumeric.Value
                    )
                }

                [void]$answers.Add("")
                [void]$answers.Add("CONVERT AND DELETE")
                [void]$answers.Add("2")
            }
        }
        else {
            [void]$answers.Add("2")

            if ($videoTestCheckBox.Checked) {
                [void]$answers.Add("2")
                [void]$answers.Add(
                    [string](Get-SelectedVideoTestPlan)
                )
                [void]$answers.Add("2")
            }
            else {
                [void]$answers.Add("1")

                [void]$answers.Add(
                    [string](Get-SelectedVideoProfileChoice)
                )
                [void]$answers.Add(
                    [string]($encoderModeCombo.SelectedIndex + 1)
                )
                [void]$answers.Add("")
                [void]$answers.Add("CONVERT AND DELETE")
                [void]$answers.Add("2")
            }
        }

        [System.IO.File]::WriteAllText(
            $answersPath,
            (($answers.ToArray() -join "`r`n") + "`r`n"),
            [System.Text.Encoding]::ASCII
        )

        $powerShellPath = Join-Path $env:SystemRoot "System32\WindowsPowerShell\v1.0\powershell.exe"

        if (-not (Test-Path -LiteralPath $powerShellPath -PathType Leaf)) {
            $powerShellPath = (Get-Command powershell.exe -ErrorAction Stop).Source
        }

        $runnerContent = @"
@echo off
type "$answersPath" | "$powerShellPath" -NoLogo -NoProfile -ExecutionPolicy Bypass -File "$workerPath" > "$script:OutputPath" 2>&1
exit /b %errorlevel%
"@

        [System.IO.File]::WriteAllText(
            $runnerPath,
            $runnerContent,
            [System.Text.Encoding]::ASCII
        )

        Append-ActivityLine -Line "Version $GuiVersion"
        Append-ActivityLine -Line "Mode: $mode"
        Append-ActivityLine -Line "Library folder: $script:CurrentTargetFolder"
        Append-ActivityLine -Line ""

        $processInfo = New-Object System.Diagnostics.ProcessStartInfo
        $processInfo.FileName = $env:ComSpec
        $processInfo.Arguments = '/d /s /c ""{0}""' -f $runnerPath
        $processInfo.UseShellExecute = $false
        $processInfo.CreateNoWindow = $true
        $processInfo.WorkingDirectory = $script:RunDirectory

        $script:RunningProcess = New-Object System.Diagnostics.Process
        $script:RunningProcess.StartInfo = $processInfo

        if (-not $script:RunningProcess.Start()) {
            throw "The optimization worker could not be started."
        }

        Set-RunControls -Running $true
        $statusLabel.Text = "Running..."

        $script:PollingTimer = New-Object System.Windows.Forms.Timer
        $script:PollingTimer.Interval = 250
        $script:PollingTimer.Add_Tick({
            Read-NewWorkerOutput

            if (
                $null -ne $script:RunningProcess -and
                $script:RunningProcess.HasExited
            ) {
                Complete-CurrentOperation
            }
        })
        $script:PollingTimer.Start()
    }
    catch {
        Disable-SleepPrevention
        Set-RunControls -Running $false
        Remove-RunFiles
        $script:RunningProcess = $null
        $script:CurrentOperation = ""
        Show-ErrorMessage -Message $_.Exception.Message
        $statusLabel.Text = "Failed to start."
    }
}

function Convert-ToDiagnosticProcessArguments {
    param([string[]]$Arguments)

    return (($Arguments | ForEach-Object {
        $value = [string]$_
        if ($value -match '[\s"]') {
            '"' + $value.Replace('"', '\"') + '"'
        }
        else {
            $value
        }
    }) -join " ")
}

function Invoke-DiagnosticProcess {
    param(
        [Parameter(Mandatory = $true)]
        [string]$FilePath,

        [Parameter(Mandatory = $true)]
        [string[]]$Arguments,

        [int]$TimeoutSeconds = 120
    )

    $startInfo = New-Object System.Diagnostics.ProcessStartInfo
    $startInfo.FileName = $FilePath
    $startInfo.Arguments = Convert-ToDiagnosticProcessArguments $Arguments
    $startInfo.UseShellExecute = $false
    $startInfo.CreateNoWindow = $true
    $startInfo.RedirectStandardOutput = $true
    $startInfo.RedirectStandardError = $true
    $startInfo.WorkingDirectory = Split-Path -Parent $FilePath

    $process = New-Object System.Diagnostics.Process
    $process.StartInfo = $startInfo
    try {
        if (-not $process.Start()) {
            throw "The process could not be started."
        }
        $stdoutTask = $process.StandardOutput.ReadToEndAsync()
        $stderrTask = $process.StandardError.ReadToEndAsync()
        if (-not $process.WaitForExit($TimeoutSeconds * 1000)) {
            try { $process.Kill() } catch {}
            throw "The process exceeded the $TimeoutSeconds second timeout."
        }
        $stdout = $stdoutTask.Result
        $stderr = $stderrTask.Result
        return [pscustomobject]@{
            ExitCode = $process.ExitCode
            StandardOutput = $stdout
            StandardError = $stderr
        }
    }
    finally {
        $process.Dispose()
    }
}

function Test-DiagnosticWebP {
    param([Parameter(Mandatory = $true)][string]$Path)

    if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) {
        return $false
    }
    try {
        $item = Get-Item -LiteralPath $Path -ErrorAction Stop
        if ($item.Length -lt 12) {
            return $false
        }
        $stream = [IO.File]::OpenRead($Path)
        try {
            $bytes = New-Object byte[] 12
            if ($stream.Read($bytes, 0, 12) -ne 12) {
                return $false
            }
        }
        finally {
            $stream.Dispose()
        }
        return (
            [Text.Encoding]::ASCII.GetString($bytes, 0, 4) -eq "RIFF" -and
            [Text.Encoding]::ASCII.GetString($bytes, 8, 4) -eq "WEBP" -and
            ([BitConverter]::ToUInt32($bytes, 4) + 8) -eq $item.Length
        )
    }
    catch {
        return $false
    }
}

function New-DiagnosticSampleImages {
    param([Parameter(Mandatory = $true)][string]$Folder)

    [void](New-Item -ItemType Directory -Path $Folder -Force)
    $opaquePath = Join-Path $Folder "Sample Opaque.png"
    $transparentPath = Join-Path $Folder "Sample Transparent.png"
    $jpegPath = Join-Path $Folder "Sample Photo.jpg"

    $bitmap = New-Object Drawing.Bitmap 800, 600
    $graphics = [Drawing.Graphics]::FromImage($bitmap)
    try {
        $graphics.Clear([Drawing.Color]::FromArgb(25, 60, 110))
        for ($index = 0; $index -lt 40; $index++) {
            $brush = New-Object Drawing.SolidBrush(
                [Drawing.Color]::FromArgb(
                    255,
                    (($index * 31) % 255),
                    (($index * 67) % 255),
                    (($index * 97) % 255)
                )
            )
            try {
                $graphics.FillRectangle(
                    $brush,
                    ($index * 37) % 760,
                    ($index * 53) % 560,
                    80,
                    60
                )
            }
            finally {
                $brush.Dispose()
            }
        }
        $bitmap.Save($opaquePath, [Drawing.Imaging.ImageFormat]::Png)
        $bitmap.Save($jpegPath, [Drawing.Imaging.ImageFormat]::Jpeg)
    }
    finally {
        $graphics.Dispose()
        $bitmap.Dispose()
    }

    $transparent = New-Object Drawing.Bitmap(
        800,
        600,
        [Drawing.Imaging.PixelFormat]::Format32bppArgb
    )
    $transparentGraphics = [Drawing.Graphics]::FromImage($transparent)
    try {
        $transparentGraphics.Clear([Drawing.Color]::Transparent)
        $brush = New-Object Drawing.SolidBrush(
            [Drawing.Color]::FromArgb(180, 255, 40, 145)
        )
        try {
            $transparentGraphics.FillEllipse($brush, 80, 60, 640, 470)
        }
        finally {
            $brush.Dispose()
        }
        $transparent.Save(
            $transparentPath,
            [Drawing.Imaging.ImageFormat]::Png
        )
    }
    finally {
        $transparentGraphics.Dispose()
        $transparent.Dispose()
    }

    return @($opaquePath, $transparentPath, $jpegPath)
}

function Invoke-DiagnosticSelfTest {
    if ($null -ne $script:RunningProcess) {
        Show-ErrorMessage -Message "Wait for the current operation to finish before running the diagnostic self-test."
        return
    }

    if (-not (Confirm-DiagnosticCollection -Title "Diagnostic self-test")) {
        return
    }

    $cwebpPath = Get-RequiredToolPath -Name "cwebp.exe"
    $ffmpegPath = Get-RequiredToolPath -Name "ffmpeg.exe"
    $ffprobePath = Get-RequiredToolPath -Name "ffprobe.exe"
    foreach ($requiredPath in @($cwebpPath, $ffmpegPath, $ffprobePath)) {
        if (-not (Test-Path -LiteralPath $requiredPath -PathType Leaf)) {
            Show-ErrorMessage -Message "Install all required tools before running the diagnostic self-test."
            return
        }
    }

    $testId = Get-Date -Format "yyyyMMdd-HHmmss-fff"
    $temporaryRoot = Join-Path (
        [IO.Path]::GetTempPath()
    ) "SYYBOTTS-Diagnostic-Self-Test-$testId"
    $selfTestReportPath = Join-Path (
        $DiagnosticsFolder
    ) "SYYBOTTS-Diagnostic-Self-Test-$testId.txt"
    $results = New-Object System.Collections.Generic.List[object]
    $temporaryCleaned = $false
    $packagePath = ""

    $recordResult = {
        param(
            [string]$Name,
            [ValidateSet("PASS", "WARNING", "FAIL")]
            [string]$Status,
            [string]$Details
        )
        $results.Add([pscustomobject]@{
            Name = $Name
            Status = $Status
            Details = $Details
        })
        Write-DiagnosticLog `
            -Force `
            -Category "SELFTEST-$Status" `
            -Message "$Name — $Details"
    }

    $savedState = [ordered]@{
        Theme = $script:CurrentTheme
        Tab = $tabControl.SelectedIndex
        ImageOperation = [string]$imageOperationCombo.Tag
        VideoOperation = [string]$videoOperationCombo.Tag
        PngHandling = $pngHandlingCombo.SelectedIndex
        JpegHandling = $jpegHandlingCombo.SelectedIndex
        PngCompression = [decimal]$pngCompressionNumeric.Value
        JpegQuality = [decimal]$jpegQualityNumeric.Value
        ImageTest = $imageTestCheckBox.Checked
        ImageTestCount = $imageTestCountCombo.SelectedIndex
        ImageTestQuality = $imageTestQualityCombo.SelectedIndex
        ImageTestCustom = [decimal]$imageTestCustomNumeric.Value
        VideoProfile = $videoProfileCombo.SelectedIndex
        EncoderMode = $encoderModeCombo.SelectedIndex
        VideoTest = $videoTestCheckBox.Checked
        VideoTestChoice = $videoTestCombo.SelectedIndex
        Advanced = $advancedVideoProfilesCheckBox.Checked
        DisableWarnings = $script:DisableWarnings
        MediaFolder = $folderTextBox.Text
        CopyDestination = $copyDestinationTextBox.Text
    }

    try {
        $script:DiagnosticSelfTestActive = $true
        $script:DisableWarnings = $true
        $runDiagnosticSelfTestButton.Enabled = $false
        $form.UseWaitCursor = $true
        [void](New-Item -ItemType Directory -Path $temporaryRoot -Force)
        [void](New-Item -ItemType Directory -Path $DiagnosticsFolder -Force)

        $statusLabel.Text = "Running diagnostic self-test..."
        Append-ActivityLine -Line ""
        Append-ActivityLine -Line "DIAGNOSTIC SELF-TEST"
        Append-ActivityLine -Line "Using generated temporary files only."
        [Windows.Forms.Application]::DoEvents()

        try {
            foreach ($theme in @("Light", "Dark", "Fight")) {
                Set-ApplicationTheme -Theme $theme
                [Windows.Forms.Application]::DoEvents()
            }
            foreach ($tabIndex in 0..2) {
                $tabControl.SelectedIndex = $tabIndex
                [Windows.Forms.Application]::DoEvents()
            }
            Set-OperationSelection -Mode Image -Selection Copy
            Set-OperationSelection -Mode Image -Selection Modify
            Set-OperationSelection -Mode Video -Selection Copy
            Set-OperationSelection -Mode Video -Selection Modify
            $script:SuppressPngHandlingNotice = $true
            $pngHandlingCombo.SelectedIndex = 0
            $pngHandlingCombo.SelectedIndex = 1
            $script:SuppressPngHandlingNotice = $false
            $jpegHandlingCombo.SelectedIndex = 1
            $jpegHandlingCombo.SelectedIndex = 0
            Set-ImageOptimizationPreset -Preset SuperLight
            if (
                $pngCompressionNumeric.Value -ne 10 -or
                $jpegQualityNumeric.Value -ne 10
            ) {
                throw "The Super Light image preset did not apply."
            }
            Set-ImageOptimizationPreset -Preset Default
            if (
                $pngCompressionNumeric.Value -ne 10 -or
                $jpegQualityNumeric.Value -ne 90
            ) {
                throw "The Default image preset did not apply."
            }
            $pngCompressionNumeric.Value = 1
            $pngCompressionNumeric.Value = 10
            $jpegQualityNumeric.Value = 0
            $jpegQualityNumeric.Value = 100
            $jpegQualityNumeric.Value = 90
            $imageTestCheckBox.Checked = $true
            $imageTestCountCombo.SelectedIndex = 0
            $imageTestCountCombo.SelectedIndex = 9
            $imageTestQualityCombo.SelectedIndex = 0
            $imageTestQualityCombo.SelectedIndex = 1
            $imageTestCustomNumeric.Value = 55
            $imageTestCheckBox.Checked = $false
            $advancedVideoProfilesCheckBox.Checked = $false
            $videoTestCheckBox.Checked = $true
            if ($videoTestCombo.Enabled) {
                throw (
                    "The additional Video Test dropdown was enabled while " +
                    "Advanced video encoding profiles were disabled."
                )
            }
            $videoTestCheckBox.Checked = $false
            $advancedVideoProfilesCheckBox.Checked = $true
            $videoTestCheckBox.Checked = $true
            if (-not $videoTestCombo.Enabled) {
                throw (
                    "The additional Video Test dropdown was not enabled " +
                    "with Advanced video encoding profiles."
                )
            }
            for (
                $choiceIndex = 0;
                $choiceIndex -lt $videoTestCombo.Items.Count;
                $choiceIndex++
            ) {
                $videoTestCombo.SelectedIndex = $choiceIndex
            }
            $videoTestCheckBox.Checked = $false
            for (
                $profileIndex = 0;
                $profileIndex -lt $videoProfileCombo.Items.Count;
                $profileIndex++
            ) {
                $videoProfileCombo.SelectedIndex = $profileIndex
            }
            $encoderModeCombo.SelectedIndex = 1
            $encoderModeCombo.SelectedIndex = 0
            & $recordResult "Interface options" "PASS" (
                "Tabs, themes, modes, image options, video options, and " +
                "test controls changed without an exception."
            )
        }
        catch {
            & $recordResult "Interface options" "FAIL" $_.Exception.Message
        }

        try {
            $layoutWarnings = New-Object System.Collections.Generic.List[object]
            $layoutIssueKeys = [Collections.Generic.HashSet[string]]::new(
                [StringComparer]::OrdinalIgnoreCase
            )
            $savedLayoutTab = $tabControl.SelectedIndex
            $savedSettingsScroll = $settingsTab.AutoScrollPosition

            foreach ($layoutTabIndex in 0..2) {
                $tabControl.SelectedIndex = $layoutTabIndex
                if ($layoutTabIndex -eq 2) {
                    $settingsTab.AutoScrollPosition = [Drawing.Point]::Empty
                }
                [Windows.Forms.Application]::DoEvents()
                foreach ($layoutIssue in @(
                    Get-DiagnosticLayoutIssues -RootControl $form
                )) {
                    $layoutKey = "$($layoutIssue.Path)|$($layoutIssue.Reason)"
                    if ($layoutIssueKeys.Add($layoutKey)) {
                        [void]$layoutWarnings.Add($layoutIssue)
                    }
                }
            }
            $tabControl.SelectedIndex = $savedLayoutTab
            $settingsTab.AutoScrollPosition = New-Object Drawing.Point(
                [math]::Abs($savedSettingsScroll.X),
                [math]::Abs($savedSettingsScroll.Y)
            )
            [Windows.Forms.Application]::DoEvents()

            foreach ($modeName in @("Image", "Video")) {
                foreach ($layoutIssue in @(
                    Show-OperationModeSelector `
                        -Mode $modeName `
                        -DiagnosticLayoutOnly
                )) {
                    [void]$layoutWarnings.Add(
                        [pscustomobject]@{
                            Path = "$modeName operation dialog/$($layoutIssue.Path)"
                            Type = $layoutIssue.Type
                            Parent = $layoutIssue.Parent
                            X = $layoutIssue.X
                            Y = $layoutIssue.Y
                            Width = $layoutIssue.Width
                            Height = $layoutIssue.Height
                            Right = $layoutIssue.Right
                            Bottom = $layoutIssue.Bottom
                            ParentClientWidth = (
                                $layoutIssue.ParentClientWidth
                            )
                            ParentClientHeight = (
                                $layoutIssue.ParentClientHeight
                            )
                            Reason = $layoutIssue.Reason
                        }
                    )
                }
            }

            if ($layoutWarnings.Count -eq 0) {
                & $recordResult "Control layout" "PASS" (
                    "Main interface and operation dialogs fit their parent " +
                    "client areas."
                )
            }
            else {
                $layoutWarningDetails = @(
                    $layoutWarnings |
                        ForEach-Object {
                            (
                                "{0} [{1}] parent={2}; " +
                                "bounds={3},{4},{5},{6}; " +
                                "parentClient={7}x{8}; {9}"
                            ) -f
                            $_.Path,
                            $_.Type,
                            $_.Parent,
                            $_.X,
                            $_.Y,
                            $_.Width,
                            $_.Height,
                            $_.ParentClientWidth,
                            $_.ParentClientHeight,
                            $_.Reason
                        }
                ) -join "`r`n"

                & $recordResult "Control layout" "WARNING" (
                    "$($layoutWarnings.Count) layout issue(s):`r`n" +
                    $layoutWarningDetails
                )
            }
        }
        catch {
            & $recordResult "Control layout" "FAIL" $_.Exception.Message
        }

        try {
            $temporarySettingsPath = Join-Path $temporaryRoot "settings.json"
            $realSettingsPath = $SettingsPath
            $realConfigurationFolder = $ConfigurationFolder
            try {
                $script:SettingsPathBeforeSelfTest = $realSettingsPath
                $ConfigurationFolder = $temporaryRoot
                $SettingsPath = $temporarySettingsPath
                [void](Save-ApplicationSettings `
                    -MediaFolder $temporaryRoot `
                    -CopyDestination (Join-Path $temporaryRoot "Destination") `
                    -DiagnosticsEnabled $true `
                    -AdvancedVideoProfilesEnabled $true `
                    -DisableWarnings $true `
                    -ModifyFilesProcessed 123 `
                    -FightModeDiscovered $true)
                $roundTrip = Get-ApplicationSettings
                if (
                    [long]$roundTrip.ModifyFilesProcessed -ne 123 -or
                    -not [bool]$roundTrip.FightModeDiscovered
                ) {
                    throw "The temporary settings values did not round-trip."
                }
            }
            finally {
                $SettingsPath = $realSettingsPath
                $ConfigurationFolder = $realConfigurationFolder
            }
            & $recordResult "Configuration round-trip" "PASS" (
                "Temporary settings saved and reloaded without replacing the user's configuration."
            )
        }
        catch {
            & $recordResult "Configuration round-trip" "FAIL" $_.Exception.Message
        }

        $sourceRoot = Join-Path $temporaryRoot "Source Library"
        $imageSourceFolder = Join-Path $sourceRoot "system-a\images"
        $videoSourceFolder = Join-Path $sourceRoot "system-a\videos"
        $imagePaths = New-DiagnosticSampleImages -Folder $imageSourceFolder
        [void](New-Item -ItemType Directory -Path $videoSourceFolder -Force)
        Copy-Item `
            -LiteralPath $imagePaths[0] `
            -Destination (Join-Path $imageSourceFolder "Duplicate.jpg") `
            -Force
        Copy-Item `
            -LiteralPath $imagePaths[0] `
            -Destination (Join-Path $imageSourceFolder "Duplicate.png") `
            -Force

        $videoSourcePath = Join-Path $videoSourceFolder "Sample Video.mp4"
        try {
            $videoCreate = Invoke-DiagnosticProcess `
                -FilePath $ffmpegPath `
                -Arguments @(
                    "-hide_banner", "-loglevel", "error", "-y",
                    "-f", "lavfi",
                    "-i", "testsrc2=size=320x240:rate=30",
                    "-f", "lavfi",
                    "-i", "sine=frequency=880:sample_rate=44100",
                    "-t", "2",
                    "-c:v", "libx264",
                    "-crf", "10",
                    "-pix_fmt", "yuv420p",
                    "-c:a", "aac",
                    "-b:a", "128k",
                    "-shortest",
                    $videoSourcePath
                )
            if (
                $videoCreate.ExitCode -ne 0 -or
                -not (Test-Path -LiteralPath $videoSourcePath -PathType Leaf)
            ) {
                throw $videoCreate.StandardError
            }
            & $recordResult "Generated test media" "PASS" (
                "Opaque, transparent, duplicate-name, JPG, and audio/video samples were created."
            )
        }
        catch {
            & $recordResult "Generated test media" "FAIL" $_.Exception.Message
            throw
        }

        try {
            $imageTestFolder = Join-Path $temporaryRoot "Application\Test Images"
            [void](New-Item -ItemType Directory -Path $imageTestFolder -Force)
            foreach ($quality in @(90, 80, 10)) {
                $testOutput = Join-Path $imageTestFolder (
                    "Sample Photo_$quality.webp"
                )
                $result = Invoke-DiagnosticProcess `
                    -FilePath $cwebpPath `
                    -Arguments @(
                        "-q", [string]$quality,
                        "-m", "6",
                        "-mt",
                        "-o", $testOutput,
                        $imagePaths[2]
                    )
                if (
                    $result.ExitCode -ne 0 -or
                    -not (Test-DiagnosticWebP -Path $testOutput)
                ) {
                    throw "Image test quality $quality failed validation."
                }
            }
            & $recordResult "Image test path" "PASS" (
                "Qualities 90, 80, and 10 produced structurally valid WebP test files."
            )
        }
        catch {
            & $recordResult "Image test path" "FAIL" $_.Exception.Message
        }

        $videoTestOutput = Join-Path $temporaryRoot "Application\Test Videos\Sample Video_Default_Medium.mp4"
        try {
            [void](New-Item `
                -ItemType Directory `
                -Path (Split-Path -Parent $videoTestOutput) `
                -Force)
            $videoTest = Invoke-DiagnosticProcess `
                -FilePath $ffmpegPath `
                -Arguments @(
                    "-hide_banner", "-loglevel", "error", "-y",
                    "-i", $videoSourcePath,
                    "-map", "0:v:0", "-map", "0:a:0?",
                    "-c:v", "libx264", "-preset", "medium",
                    "-crf", "24", "-pix_fmt", "yuv420p",
                    "-r", "30", "-c:a", "aac", "-b:a", "96k",
                    "-movflags", "+faststart",
                    $videoTestOutput
                )
            $probe = Invoke-DiagnosticProcess `
                -FilePath $ffprobePath `
                -Arguments @(
                    "-v", "error",
                    "-show_entries", "stream=codec_type",
                    "-of", "csv=p=0",
                    $videoTestOutput
                )
            if (
                $videoTest.ExitCode -ne 0 -or
                $probe.ExitCode -ne 0 -or
                $probe.StandardOutput -notmatch "video" -or
                $probe.StandardOutput -notmatch "audio"
            ) {
                throw "The video test output failed stream validation."
            }
            & $recordResult "Video test path" "PASS" (
                "The generated MP4 passed video and audio stream inspection."
            )
        }
        catch {
            & $recordResult "Video test path" "FAIL" $_.Exception.Message
        }

        try {
            $sourceHashesBefore = @{}
            Get-ChildItem -LiteralPath $sourceRoot -File -Recurse |
                ForEach-Object {
                    $sourceHashesBefore[$_.FullName] = (
                        Get-FileHash -LiteralPath $_.FullName -Algorithm SHA256
                    ).Hash
                }

            $copyDestination = Join-Path $temporaryRoot "Copy Destination"
            foreach ($sourceFile in Get-ChildItem -LiteralPath $sourceRoot -File -Recurse) {
                $relative = $sourceFile.FullName.Substring(
                    $sourceRoot.Length
                ).TrimStart("\")
                $selectedSource = $sourceFile.FullName
                $destinationRelative = $relative
                if (
                    $sourceFile.Name -eq "Sample Photo.jpg" -and
                    (Test-Path -LiteralPath (
                        Join-Path $imageTestFolder "Sample Photo_90.webp"
                    ))
                ) {
                    $candidate = Join-Path (
                        $imageTestFolder
                    ) "Sample Photo_90.webp"
                    if (
                        (Get-Item -LiteralPath $candidate).Length -lt
                        $sourceFile.Length
                    ) {
                        $selectedSource = $candidate
                        $destinationRelative = [IO.Path]::ChangeExtension(
                            $relative,
                            ".webp"
                        )
                    }
                }
                elseif (
                    $sourceFile.Name -eq "Sample Video.mp4" -and
                    (Test-Path -LiteralPath $videoTestOutput)
                ) {
                    if (
                        (Get-Item -LiteralPath $videoTestOutput).Length -lt
                        $sourceFile.Length
                    ) {
                        $selectedSource = $videoTestOutput
                    }
                }

                $destinationPath = Join-Path (
                    $copyDestination
                ) $destinationRelative
                [void](New-Item `
                    -ItemType Directory `
                    -Path (Split-Path -Parent $destinationPath) `
                    -Force)
                Copy-Item `
                    -LiteralPath $selectedSource `
                    -Destination $destinationPath `
                    -Force
            }
            $manifestPath = Join-Path $copyDestination ".syybott-copy-manifest.jsonl"
            [pscustomobject]@{
                Source = $sourceRoot
                Destination = $copyDestination
                CompletedUtc = [DateTime]::UtcNow.ToString("o")
            } | ConvertTo-Json -Compress |
                Set-Content -LiteralPath $manifestPath -Encoding UTF8
            @(
                "Diagnostic Copy Mode report"
                "Source: $sourceRoot"
                "Destination: $copyDestination"
                "Manifest: $manifestPath"
            ) | Set-Content `
                -LiteralPath (Join-Path $copyDestination "Copy-Mode-Report.txt") `
                -Encoding UTF8

            foreach ($entry in $sourceHashesBefore.GetEnumerator()) {
                $afterHash = (
                    Get-FileHash -LiteralPath $entry.Key -Algorithm SHA256
                ).Hash
                if ($afterHash -ne $entry.Value) {
                    throw "Copy Mode equivalent changed a source file."
                }
            }
            & $recordResult "Copy Mode paths" "PASS" (
                "Image/video folder recreation, source preservation, and manifest writing passed."
            )
        }
        catch {
            & $recordResult "Copy Mode paths" "FAIL" $_.Exception.Message
        }

        try {
            $modifyRoot = Join-Path $temporaryRoot "Modify Clones"
            Copy-Item -LiteralPath $sourceRoot -Destination $modifyRoot -Recurse
            $modifyPng = Get-ChildItem `
                -LiteralPath $modifyRoot `
                -Filter "Sample Opaque.png" `
                -File `
                -Recurse |
                Select-Object -First 1
            $modifyWebP = [IO.Path]::ChangeExtension(
                $modifyPng.FullName,
                ".webp"
            )
            $modifyImage = Invoke-DiagnosticProcess `
                -FilePath $cwebpPath `
                -Arguments @(
                    "-z", "9",
                    "-o", $modifyWebP,
                    $modifyPng.FullName
                )
            if (
                $modifyImage.ExitCode -ne 0 -or
                -not (Test-DiagnosticWebP -Path $modifyWebP)
            ) {
                throw "The cloned image replacement failed validation."
            }
            Remove-Item -LiteralPath $modifyPng.FullName -Force

            $modifyVideo = Get-ChildItem `
                -LiteralPath $modifyRoot `
                -Filter "Sample Video.mp4" `
                -File `
                -Recurse |
                Select-Object -First 1
            $modifyVideoOutput = "$($modifyVideo.FullName).optimized.mp4"
            $modifyVideoResult = Invoke-DiagnosticProcess `
                -FilePath $ffmpegPath `
                -Arguments @(
                    "-hide_banner", "-loglevel", "error", "-y",
                    "-i", $modifyVideo.FullName,
                    "-c:v", "libx264", "-preset", "medium",
                    "-crf", "24", "-pix_fmt", "yuv420p",
                    "-c:a", "aac", "-b:a", "96k",
                    $modifyVideoOutput
                )
            $modifyProbe = Invoke-DiagnosticProcess `
                -FilePath $ffprobePath `
                -Arguments @(
                    "-v", "error",
                    "-show_entries", "stream=codec_type",
                    "-of", "csv=p=0",
                    $modifyVideoOutput
                )
            if (
                $modifyVideoResult.ExitCode -ne 0 -or
                $modifyProbe.ExitCode -ne 0 -or
                $modifyProbe.StandardOutput -notmatch "video"
            ) {
                throw "The cloned video replacement failed validation."
            }
            if (
                (Get-Item -LiteralPath $modifyVideoOutput).Length -lt
                $modifyVideo.Length
            ) {
                Remove-Item -LiteralPath $modifyVideo.FullName -Force
            }
            else {
                Remove-Item -LiteralPath $modifyVideoOutput -Force
            }
            @(
                "Diagnostic Modify Mode report"
                "Isolated clone: $modifyRoot"
                "Source library was not used."
            ) | Set-Content `
                -LiteralPath (Join-Path $modifyRoot "Modify-Mode-Report.txt") `
                -Encoding UTF8
            & $recordResult "Modify Mode paths" "PASS" (
                "Image and video replacements succeeded only inside isolated cloned folders."
            )
        }
        catch {
            & $recordResult "Modify Mode paths" "FAIL" $_.Exception.Message
        }
    }
    catch {
        & $recordResult "Self-test execution" "FAIL" $_.Exception.Message
    }
    finally {
        try {
            $script:SuppressPngCompressionNotice = $true
            $script:SuppressPngHandlingNotice = $true
            $script:DisableWarnings = $true
            Set-OperationSelection `
                -Mode Image `
                -Selection $savedState.ImageOperation
            Set-OperationSelection `
                -Mode Video `
                -Selection $savedState.VideoOperation
            $pngHandlingCombo.SelectedIndex = $savedState.PngHandling
            $jpegHandlingCombo.SelectedIndex = $savedState.JpegHandling
            $pngCompressionNumeric.Value = $savedState.PngCompression
            $jpegQualityNumeric.Value = $savedState.JpegQuality
            $imageTestCountCombo.SelectedIndex = $savedState.ImageTestCount
            $imageTestQualityCombo.SelectedIndex = $savedState.ImageTestQuality
            $imageTestCustomNumeric.Value = $savedState.ImageTestCustom
            $videoProfileCombo.SelectedIndex = $savedState.VideoProfile
            $encoderModeCombo.SelectedIndex = $savedState.EncoderMode
            $videoTestCombo.SelectedIndex = $savedState.VideoTestChoice
            $imageTestCheckBox.Checked = $savedState.ImageTest
            $videoTestCheckBox.Checked = $savedState.VideoTest
            $advancedVideoProfilesCheckBox.Checked = $savedState.Advanced
            $folderTextBox.Text = $savedState.MediaFolder
            $copyDestinationTextBox.Text = $savedState.CopyDestination
            $tabControl.SelectedIndex = $savedState.Tab
            Set-ApplicationTheme -Theme $savedState.Theme
        }
        catch {
            & $recordResult "Interface state restore" "WARNING" $_.Exception.Message
        }
        finally {
            $script:SuppressPngCompressionNotice = $false
            $script:SuppressPngHandlingNotice = $false
            $script:DisableWarnings = $savedState.DisableWarnings
            $script:DiagnosticSelfTestActive = $false
            $form.UseWaitCursor = $false
            $runDiagnosticSelfTestButton.Enabled = $true
            Update-WarningControls
        }

        try {
            if (Test-Path -LiteralPath $temporaryRoot) {
                Remove-Item `
                    -LiteralPath $temporaryRoot `
                    -Recurse `
                    -Force `
                    -ErrorAction Stop
            }
            $temporaryCleaned = -not (Test-Path -LiteralPath $temporaryRoot)
        }
        catch {
            $temporaryCleaned = $false
            & $recordResult "Temporary cleanup" "WARNING" $_.Exception.Message
        }

        $passed = @($results | Where-Object Status -eq "PASS").Count
        $warnings = @($results | Where-Object Status -eq "WARNING").Count
        $failed = @($results | Where-Object Status -eq "FAIL").Count
        @(
            "SYYBOTT'S Media Optimizer Diagnostic Self-Test"
            "Created: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss zzz')"
            "GUI version: $GuiVersion"
            "Engine version: $EngineVersion"
            ""
            "Passed: $passed"
            "Warnings: $warnings"
            "Failed: $failed"
            ""
            "RESULTS"
            "-------"
            ($results | ForEach-Object {
                "[$($_.Status)] $($_.Name): $($_.Details)"
            })
        ) | Set-Content `
            -LiteralPath $selfTestReportPath `
            -Encoding UTF8

        $packagePath = New-DiagnosticPackage `
            -AdditionalReportPath $selfTestReportPath
        $statusLabel.Text = if ($failed -eq 0) {
            "Diagnostic self-test finished."
        } else {
            "Diagnostic self-test found failures."
        }

        [void][Windows.Forms.MessageBox]::Show(
            $form,
            (
                "Tests passed: $passed`r`n" +
                "Warnings: $warnings`r`n" +
                "Failures: $failed`r`n`r`n" +
                "Diagnostic package:`r`n$packagePath"
            ),
            "Diagnostic self-test results",
            [Windows.Forms.MessageBoxButtons]::OK,
            $(if ($failed -eq 0) {
                [Windows.Forms.MessageBoxIcon]::Information
            } else {
                [Windows.Forms.MessageBoxIcon]::Warning
            })
        )
    }
}

$browseButton.Add_Click({
    $dialog = New-Object System.Windows.Forms.FolderBrowserDialog
    $dialog.Description = "Select the image or video library folder"
    $dialog.ShowNewFolderButton = $false

    if (Test-Path -LiteralPath $folderTextBox.Text -PathType Container) {
        $dialog.SelectedPath = $folderTextBox.Text
    }

    if ($dialog.ShowDialog($form) -eq [System.Windows.Forms.DialogResult]::OK) {
        $selectedFolder = [System.IO.Path]::GetFullPath($dialog.SelectedPath)
        $folderTextBox.Text = $selectedFolder
        [void](Save-MediaFolderSetting -MediaFolder $selectedFolder)
    }

    $dialog.Dispose()
})

$downloadToolsButton.Add_Click({
    Write-DiagnosticLog `
        -Category "TOOLS" `
        -Message "Download/Update Tools clicked."
    Request-ToolDownload
})

$diagnosticLoggingCheckBox.Add_CheckedChanged({
    if ($script:SuppressDiagnosticToggle) {
        return
    }

    if ($diagnosticLoggingCheckBox.Checked) {
        if (-not (Confirm-DiagnosticCollection)) {
            $script:SuppressDiagnosticToggle = $true
            try {
                $diagnosticLoggingCheckBox.Checked = $false
            }
            finally {
                $script:SuppressDiagnosticToggle = $false
            }
            return
        }
        $script:DiagnosticsEnabled = $true
        [void](Initialize-DiagnosticSession)
        [void](Save-ApplicationSettings -DiagnosticsEnabled $true)
        $diagnosticsStatusLabel.Text = (
            "Logging enabled. Ctrl+Shift+D creates a diagnostic package."
        )
        Write-DiagnosticLog `
            -Category "SETTINGS" `
            -Message "Diagnostic logging enabled by user."
        Write-DiagnosticApplicationState `
            -Reason "Diagnostic logging enabled"
        Write-DiagnosticControlSnapshot `
            -Reason "Diagnostic logging enabled"
    }
    else {
        Write-DiagnosticLog `
            -Category "SETTINGS" `
            -Message "Diagnostic logging disabled by user."
        [void](Save-ApplicationSettings -DiagnosticsEnabled $false)
        $script:DiagnosticsEnabled = $false
        $diagnosticsStatusLabel.Text = (
            "Ctrl+Shift+D creates a one-time diagnostic package."
        )
    }
})

