$pngHandlingCombo.Add_SelectedIndexChanged({
    Write-DiagnosticLog `
        -Category "OPTION" `
        -Message "PNG handling changed to '$($pngHandlingCombo.SelectedItem)'; focused=$($pngHandlingCombo.Focused)."

    if (
        $pngHandlingCombo.SelectedIndex -eq 0 -and
        $pngHandlingCombo.Focused -and
        -not $script:SuppressPngHandlingNotice -and
        -not $script:DisableWarnings
    ) {
        $message = @"
PNG to WebP conversion is lossless and should not affect image quality.

WebP generally provides better compression and can significantly reduce the size of your media library.

Skip PNG conversion anyway?
"@
        if (-not (Show-WarningConfirmation `
            -Message $message `
            -Title "Skip PNG conversion?")) {
            $script:SuppressPngHandlingNotice = $true
            try {
                $pngHandlingCombo.SelectedIndex = 1
            }
            finally {
                $script:SuppressPngHandlingNotice = $false
            }
        }
    }

    $pngCompressionNumeric.Enabled = (
        -not $imageTestCheckBox.Checked -and
        $pngHandlingCombo.SelectedIndex -gt 0
    )
    Update-StartAvailability
    Write-DiagnosticControlSnapshot -Reason "After PNG handling selection"
    Write-DiagnosticApplicationState -Reason "After PNG handling selection"
})

$jpegHandlingCombo.Add_SelectedIndexChanged({
    Write-DiagnosticLog `
        -Category "OPTION" `
        -Message "JPG/JPEG handling changed to '$($jpegHandlingCombo.SelectedItem)'; focused=$($jpegHandlingCombo.Focused)."

    $jpegQualityNumeric.Enabled = (
        $jpegHandlingCombo.SelectedIndex -gt 0
    )

    if (
        $jpegHandlingCombo.SelectedIndex -gt 0 -and
        $jpegHandlingCombo.Focused -and
        [string]$imageOperationCombo.Tag -ne "Copy"
    ) {
        $message = @"
JPG/JPEG conversion is lossy.

JPG/JPEG conversions keep the smaller valid file. Duplicate groups keep the smallest valid WebP. Transparent PNG groups are protected from lossy or nontransparent replacements.

Back up the library first, or test a copied sample folder before processing the full library.

Enable this JPG/JPEG mode?
"@

        if (-not (Show-WarningConfirmation -Message $message)) {
            $jpegHandlingCombo.SelectedIndex = 0
        }
    }

    Write-DiagnosticControlSnapshot `
        -Reason "After JPG/JPEG handling selection"
    Write-DiagnosticApplicationState `
        -Reason "After JPG/JPEG handling selection"
})

$imageTestCheckBox.Add_CheckedChanged({
    $testMode = $imageTestCheckBox.Checked
    Write-DiagnosticLog `
        -Category "OPTION" `
        -Message "JPG/JPEG Test Batch changed to $testMode."

    if ($testMode -and -not $script:DisableWarnings) {
        $message = @"
Once the test has completed click the 'Open Folder' button to view the images created.

Review the test images on the target device before completing a full library conversion.
"@

        Show-DiagnosticInformationMessage `
            -Message $message `
            -Title "JPG/JPEG Test Batch"
    }

    $imageTestCountCombo.Enabled = $testMode
    $imageTestQualityCombo.Enabled = $testMode
    $imageTestCustomNumeric.Enabled = (
        $testMode -and
        $imageTestQualityCombo.SelectedIndex -eq 1
    )

    $jpegHandlingCombo.Enabled = -not $testMode
    $pngHandlingCombo.Enabled = -not $testMode
    $pngCompressionNumeric.Enabled = (
        -not $testMode -and
        $pngHandlingCombo.SelectedIndex -gt 0
    )
    $jpegQualityNumeric.Enabled = (
        -not $testMode -and
        $jpegHandlingCombo.SelectedIndex -gt 0
    )
    Update-StartAvailability
    Write-DiagnosticControlSnapshot `
        -Reason "After JPG/JPEG Test Batch toggle"
    Write-DiagnosticApplicationState `
        -Reason "After JPG/JPEG Test Batch toggle"
})

$imageTestQualityCombo.Add_SelectedIndexChanged({
