$pngCompressionNumeric.Add_ValueChanged({
    $newValue = [int]$pngCompressionNumeric.Value

    if ($script:SuppressPngCompressionNotice) {
        $script:LastPngCompressionValue = $newValue
        return
    }

    $wasLowered = (
        $newValue -lt $script:LastPngCompressionValue -and
        $newValue -lt 10
    )

    if (
        $wasLowered -and
        -not $script:PngCompressionLoweringNoticeShown -and
        -not $script:DisableWarnings
    ) {
        $script:PngCompressionLoweringNoticeShown = $true

        $message = @"
This controls lossless compression effort only. It does not reduce or alter image quality.

The higher the compression, the more space you can save, but the longer the script will take.

It is highly advised that you use the highest compression level and wait for the script to finish. It may take a long time, but it is safe to stop and restart the script as needed.

"@

        [void][System.Windows.Forms.MessageBox]::Show(
            $message,
            "PNG lossless compression",
            [System.Windows.Forms.MessageBoxButtons]::OK,
            [System.Windows.Forms.MessageBoxIcon]::Information
        )

        $script:SuppressPngCompressionNotice = $true

        try {
            $pngCompressionNumeric.Value = 10
        }
        finally {
            $script:SuppressPngCompressionNotice = $false
        }

        $script:LastPngCompressionValue = 10
        return
    }

    $script:LastPngCompressionValue = $newValue
})

