$cancelButton.Add_Click({
    if ($null -eq $script:RunningProcess) {
        return
    }

    $cancelMessage = if ($script:CurrentOperation -eq "ToolDownload") {
        "Stop downloading and installing the required tools?"
    }
    else {
        "Stop the current run? The active file may be left in a temporary or rollback state until the worker exits."
    }

    $cancelTitle = if ($script:CurrentOperation -eq "ToolDownload") {
        "Cancel tool download"
    }
    else {
        "Cancel optimization"
    }

    if (-not $script:DisableWarnings) {
        $answer = [System.Windows.Forms.MessageBox]::Show(
            $cancelMessage,
            $cancelTitle,
            [System.Windows.Forms.MessageBoxButtons]::YesNo,
            [System.Windows.Forms.MessageBoxIcon]::Warning,
            [System.Windows.Forms.MessageBoxDefaultButton]::Button2
        )

        if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) {
            return
        }
    }

    $script:CancelRequested = $true
    $statusLabel.Text = "Cancelling..."
    $cancelButton.Enabled = $false

    try {
        $taskkillInfo = New-Object System.Diagnostics.ProcessStartInfo
        $taskkillInfo.FileName = "taskkill.exe"
        $taskkillInfo.Arguments = "/PID $($script:RunningProcess.Id) /T /F"
        $taskkillInfo.UseShellExecute = $false
        $taskkillInfo.CreateNoWindow = $true

        $taskkillProcess = [System.Diagnostics.Process]::Start($taskkillInfo)
        $taskkillProcess.WaitForExit()
        $taskkillProcess.Dispose()
    }
    catch {
        Append-ActivityLine -Line "CANCEL ERROR: $($_.Exception.Message)"
    }
})

