$script:ThreadExceptionHandler = (
    [System.Threading.ThreadExceptionEventHandler]{
        param($sender, $eventArgs)

        Write-DiagnosticException `
            -Source "WinForms ThreadException" `
            -Exception $eventArgs.Exception
    }
)
[System.Windows.Forms.Application]::add_ThreadException(
    $script:ThreadExceptionHandler
)

$script:UnhandledExceptionHandler = (
    [System.UnhandledExceptionEventHandler]{
        param($sender, $eventArgs)

        $exception = $eventArgs.ExceptionObject -as [System.Exception]
        if ($null -ne $exception) {
            Write-DiagnosticException `
                -Source "AppDomain UnhandledException" `
                -Exception $exception
        }
        else {
            Write-DiagnosticLog `
                -Category "ERROR" `
                -Message "AppDomain UnhandledException: $($eventArgs.ExceptionObject)"
        }
    }
)
[System.AppDomain]::CurrentDomain.add_UnhandledException(
    $script:UnhandledExceptionHandler
)

$form.Add_FormClosing({
    param($sender, $eventArgs)

    Write-DiagnosticLog `
        -Category "WINDOW" `
        -Message "Application close requested."
    Write-DiagnosticControlSnapshot `
        -Reason "Application closing"
    Write-DiagnosticApplicationState `
        -Reason "Application closing"

    if ($null -ne $script:RunningProcess -and -not $script:RunningProcess.HasExited) {
        if (-not $script:DisableWarnings) {
            $answer = [System.Windows.Forms.MessageBox]::Show(
                "An optimization run is active. Cancel it and close the app?",
                "Active optimization",
                [System.Windows.Forms.MessageBoxButtons]::YesNo,
                [System.Windows.Forms.MessageBoxIcon]::Warning,
                [System.Windows.Forms.MessageBoxDefaultButton]::Button2
            )

            if ($answer -ne [System.Windows.Forms.DialogResult]::Yes) {
                $eventArgs.Cancel = $true
                Write-DiagnosticLog `
                    -Category "WINDOW" `
                    -Message "Application close cancelled by user."
                return
            }
        }

        $script:CancelRequested = $true

        try {
            Start-Process `
                -FilePath "taskkill.exe" `
                -ArgumentList @("/PID", $script:RunningProcess.Id, "/T", "/F") `
                -WindowStyle Hidden `
                -Wait
        }
        catch {
            # The process may already have exited.
        }
    }

    if ($null -ne $script:PollingTimer) {
        $script:PollingTimer.Stop()
        $script:PollingTimer.Dispose()
    }

    if ($null -ne $themeAnimationTimer) {
        $themeAnimationTimer.Stop()
        $themeAnimationTimer.Dispose()
    }

    if ($null -ne $script:FightMascotImage) {
        $script:FightMascotImage.Dispose()
        $script:FightMascotImage = $null
    }

    Disable-SleepPrevention
    Save-ModifyProgress -Force
    Remove-RunFiles

    if ($null -ne $script:ThreadExceptionHandler) {
        [System.Windows.Forms.Application]::remove_ThreadException(
            $script:ThreadExceptionHandler
        )
        $script:ThreadExceptionHandler = $null
    }

    if ($null -ne $script:UnhandledExceptionHandler) {
        [System.AppDomain]::CurrentDomain.remove_UnhandledException(
            $script:UnhandledExceptionHandler
        )
        $script:UnhandledExceptionHandler = $null
    }

    Write-DiagnosticLog `
        -Category "WINDOW" `
        -Message "Application shutdown cleanup completed."
})

Set-ApplicationTheme -Theme "Dark"
[void](Update-ToolStatus)
Initialize-DisplayScaling
Update-WarningControls

